SELECT b.id, v.page_index, v.text, v.blocks::jsonb
  FROM (VALUES
    ('im-the-colour-of-honey', 0, $$My name is Amanda. I live with my Mummy, my Daddy and my dog Porsha. My Daddy says I’m the colour of honey. My Mummy says I look like a beautiful sunset.$$, $$[{"role": "BODY", "text": "My name is Amanda. I live with my Mummy, my Daddy and my dog Porsha.", "bbox": [710.3, 161.1, 1021.9, 239.1], "size": 24.0}, {"role": "BODY", "text": "My Daddy says I’m the colour of honey.", "bbox": [740.2, 269.1, 992.0, 320.1], "size": 24.0}, {"role": "BODY", "text": "My Mummy says I look like a beautiful sunset.", "bbox": [718.0, 350.1, 1014.2, 401.1], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 1, $$But I don’t look like either of them. Only Porsha is brown like me!$$, $$[{"role": "BODY", "text": "But I don’t look like either of them. Only Porsha is brown like me!", "bbox": [689.2, 202.8, 1011.6, 280.8], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 2, $$When we go out some people stare at us, or ask us lots of questions.$$, $$[{"role": "BODY", "text": "When we go out some people stare at us, or ask us lots of questions.", "bbox": [626.3, 304.9, 831.2, 409.9], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 3, $$“Is that your Aunty?” asks the woman at the store. No! It’s my Mummy!$$, $$[{"role": "BODY", "text": "“Is that your Aunty?” asks the woman at the store.", "bbox": [101.1, 99.8, 326.0, 177.8], "size": 24.0}, {"role": "BODY", "text": "No! It’s my Mummy!", "bbox": [707.9, 151.0, 995.7, 379.1], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 4, $$asks “Is that the your man in Teacher?” the park. No! It’s my Daddy!$$, $$[{"role": "BODY", "text": "asks “Is that the your man in Teacher?” the park.", "bbox": [75.0, 140.3, 352.1, 191.3], "size": 24.0}, {"role": "BODY", "text": "No! It’s my Daddy!", "bbox": [707.9, 151.0, 995.7, 399.1], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 5, $$“Why don’t you look like them?” “Because I’m the colour of honey. And I look like a beautiful sunset.”$$, $$[{"role": "BODY", "text": "“Why don’t you look like them?”", "bbox": [172.5, 192.3, 394.4, 243.3], "size": 24.0}, {"role": "BODY", "text": "“Because I’m the colour of honey. And I look like a beautiful sunset.”", "bbox": [135.1, 301.4, 431.8, 379.4], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 6, $$“But your Daddy is like a night sky,” says the woman at the store. “And your Mummy is as white as the blank pages in a book,” says the man in the park.$$, $$[{"role": "BODY", "text": "“But your Daddy is like a night sky,” says the woman at the store.", "bbox": [656.2, 117.3, 1046.0, 168.3], "size": 24.0}, {"role": "BODY", "text": "“And your Mummy is as white as the blank pages in a book,” says the man in the park.", "bbox": [671.6, 198.3, 1030.6, 276.3], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 7, $$you “Whyokt?” differen lo do so$$, $$[{"role": "BODY", "text": "you “Whyokt?” differen lo do so", "bbox": [127.6, 160.8, 428.6, 395.7], "size": 61.6}]$$),
    ('im-the-colour-of-honey', 8, $$The next day I wrap a towel on my head and swing it around just like Mummy does with her hair. “Is that your Aunty?” asks the woman at the store. “No, that’s my Mummy!”$$, $$[{"role": "BODY", "text": "The next day I wrap a towel on my head and swing it around just like Mummy does with her hair.", "bbox": [697.1, 142.7, 1003.7, 247.7], "size": 24.0}, {"role": "BODY", "text": "“Is that your Aunty?” asks the woman at the store.", "bbox": [709.8, 277.7, 991.0, 328.7], "size": 24.0}, {"role": "SFX", "text": "“No, that’s my Mummy!”", "bbox": [725.7, 391.2, 975.1, 470.4], "size": 36.0}]$$),
