    ('im-the-colour-of-honey', 10, $$I mummyeon’t lookhylikd dadd “W y?”ndu, ayo “Amanda, show me that smile, that’s just I don’t like your feel Daddy’s.” like smiling. “Come on Amanda, look at your dimple. It’s so pretty, just like your Mummy’s!”$$, $$[{"role": "BODY", "text": "I mummyeon’t lookhylikd dadd “W y?”ndu, ayo", "bbox": [324.5, 81.0, 480.9, 205.1], "size": 26.4}, {"role": "BODY", "text": "“Amanda, show me that smile, that’s just I don’t like your feel Daddy’s.” like smiling.", "bbox": [628.2, 65.9, 1072.6, 182.9], "size": 24.0}, {"role": "BODY", "text": "“Come on Amanda, look at your dimple. It’s so pretty, just like your Mummy’s!”", "bbox": [665.1, 210.9, 1035.7, 288.9], "size": 24.0}]$$),
    ('im-the-colour-of-honey', 11, $$Mummy and Daddy make me smile. And I make them smile too! “Look!” I say, “My teeth are white, just like yours.” “Yes, and your heart is red, just like ours.”$$, $$[{"role": "BODY", "text": "Mummy and Daddy make me smile. And I make them smile too!", "bbox": [118.8, 138.4, 416.9, 216.4], "size": 24.0}, {"role": "BODY", "text": "“Look!” I say, “My teeth are white, just like yours.”", "bbox": [109.4, 248.5, 426.4, 299.5], "size": 24.0}, {"role": "BODY", "text": "“Yes, and your heart is red, just like ours.”", "bbox": [121.5, 327.4, 414.2, 378.4], "size": 24.0}]$$),
