    ('julia-loves-books', 11, $$gode Na Merci Dankie Enkosi Ngiyabonga Asante Thank you Salamat leboga Kea We will love Ndzi your book. khensa Shukran Tak$$, $$[{"role": "BODY", "text": "gode Na", "bbox": [455.6, 28.0, 507.5, 79.0], "size": 22.6}, {"role": "BODY", "text": "Merci", "bbox": [138.2, 39.5, 234.2, 95.7], "size": 38.9}, {"role": "BODY", "text": "Dankie", "bbox": [324.1, 100.9, 428.2, 145.5], "size": 33.5}, {"role": "BODY", "text": "Enkosi", "bbox": [34.8, 157.7, 140.3, 188.6], "size": 30.9}, {"role": "BODY", "text": "Ngiyabonga", "bbox": [440.4, 176.0, 520.9, 202.2], "size": 14.2}, {"role": "BODY", "text": "Asante", "bbox": [232.7, 181.3, 321.2, 205.2], "size": 23.8}, {"role": "BODY", "text": "Thank you", "bbox": [505.1, 225.6, 552.7, 262.2], "size": 15.4}, {"role": "BODY", "text": "Salamat leboga Kea", "bbox": [316.6, 357.5, 554.6, 411.9], "size": 17.9}, {"role": "BODY", "text": "We will love Ndzi your book. khensa", "bbox": [688.7, 77.1, 1109.8, 191.5], "size": 52.0}, {"role": "BODY", "text": "Shukran", "bbox": [723.0, 415.5, 833.6, 446.6], "size": 26.3}, {"role": "BODY", "text": "Tak", "bbox": [1063.4, 317.2, 1116.9, 354.3], "size": 31.8}]$$),
