    ('lets-go-on-a-litter-hunt', 0, $$Papa says, “This yard is a MESS. The wind blew the rubbish in.” Mama says, “Let’s go on a litter hunt. First look for tins.” Papa says, “Wear these gloves.” Yuck!$$, $$[{"role": "SFX", "text": "Papa says, “This yard is a MESS. The wind blew the rubbish in.” Mama says, “Let’s go on a litter hunt. First look for tins.” Papa says, “Wear these gloves.” Yuck!", "bbox": [56.7, 73.9, 526.1, 282.9], "size": 34.5}]$$),
    ('lets-go-on-a-litter-hunt', 1, $$We’re going on a tin hunt. We look up high and down low. We look under the bushes and against the fence.$$, $$[{"role": "BODY", "text": "We’re going on a tin hunt. We look up high and down low. We look under the bushes and against the fence.", "bbox": [126.4, 73.9, 440.6, 180.8], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 2, $$We’ve found red tins and green tins, rusty tins and shiny tins, clean tins and dirty tins. Yuck!$$, $$[{"role": "BODY", "text": "We’ve found red tins and green tins, rusty tins and shiny tins, clean tins and dirty tins.", "bbox": [158.0, 73.9, 409.1, 175.1], "size": 22.0}, {"role": "SFX", "text": "Yuck!", "bbox": [837.8, 144.9, 1021.3, 215.5], "size": 70.6}]$$),
    ('lets-go-on-a-litter-hunt', 3, $$What must we do with all these tins? Find a bin and put them in! Now look for plastic.$$, $$[{"role": "BODY", "text": "What must we do with all these tins?", "bbox": [96.0, 213.5, 471.1, 235.5], "size": 22.0}, {"role": "BODY", "text": "Find a bin and put them in!", "bbox": [700.9, 64.0, 974.6, 86.0], "size": 22.0}, {"role": "BODY", "text": "Now look for plastic.", "bbox": [613.5, 162.7, 723.5, 211.1], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 4, $$We’re going on a plastic hunt. We look up high and down low. We look behind the chicken coop and in front of the house.$$, $$[{"role": "BODY", "text": "We’re going on a plastic hunt. We look up high and down low. We look behind the chicken coop and in front of the house.", "bbox": [176.6, 233.3, 508.1, 334.5], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 5, $$We’ve found milk bottles and bottle tops, shopping bags and sucker sticks, straws and broken buckets. Yuck!$$, $$[{"role": "BODY", "text": "We’ve found milk bottles and bottle tops, shopping bags and sucker sticks, straws and broken buckets.", "bbox": [117.8, 73.9, 449.2, 175.1], "size": 22.0}, {"role": "SFX", "text": "Yuck!", "bbox": [845.6, 356.9, 1029.1, 427.5], "size": 70.6}]$$),
    ('lets-go-on-a-litter-hunt', 6, $$What must we do with all this plastic? Find a bin and put it in! Now look for paper.$$, $$[{"role": "BODY", "text": "What must we do with all this plastic?", "bbox": [90.1, 243.8, 477.0, 265.8], "size": 22.0}, {"role": "BODY", "text": "Find a bin and put it in!", "bbox": [719.1, 64.0, 956.4, 86.0], "size": 22.0}, {"role": "BODY", "text": "Now look for paper.", "bbox": [617.7, 161.6, 719.2, 210.0], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 7, $$We’re going on a paper hunt. We look up high and down low. We look near the water barrel and on top of the bench.$$, $$[{"role": "BODY", "text": "We’re going on a paper hunt. We look up high and down low. We look near the water barrel and on top of the bench.", "bbox": [190.2, 235.5, 504.4, 336.7], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 8, $$We’ve found wet paper and dry paper, cardboard boxes and newspaper, old paper plates and dirty tissues. Yuck!$$, $$[{"role": "BODY", "text": "We’ve found wet paper and dry paper, cardboard boxes and newspaper, old paper plates and dirty tissues.", "bbox": [88.1, 73.9, 479.0, 148.7], "size": 22.0}, {"role": "SFX", "text": "Yuck!", "bbox": [829.3, 300.9, 1012.8, 371.5], "size": 70.6}]$$),
    ('lets-go-on-a-litter-hunt', 9, $$What must we do with all this paper? Find a bin and put it in! What else can you look for? Hmm …$$, $$[{"role": "BODY", "text": "What must we do with all this paper?", "bbox": [94.4, 235.5, 472.8, 257.5], "size": 22.0}, {"role": "BODY", "text": "Find a bin and put it in!", "bbox": [726.2, 56.9, 963.4, 78.9], "size": 22.0}, {"role": "BODY", "text": "What else can you look for? Hmm …", "bbox": [607.5, 141.4, 751.7, 216.2], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 10, $$There’s nnoo mmoorree mmeessss! Wow! This place is so clean. Thanks, litter hunters.$$, $$[{"role": "BODY", "text": "There’s nnoo mmoorree mmeessss!", "bbox": [199.6, 72.0, 316.0, 120.4], "size": 22.0}, {"role": "BODY", "text": "Wow! This place is so clean. Thanks, litter hunters.", "bbox": [667.0, 54.8, 870.9, 156.0], "size": 22.0}]$$),
    ('lets-go-on-a-litter-hunt', 11, $$Find a bin and put it in! You deserve a treat! And remember … what must you do with your litter?$$, $$[{"role": "BODY", "text": "Find a bin and put it in!", "bbox": [731.8, 73.9, 969.1, 95.9], "size": 22.0}, {"role": "BODY", "text": "You deserve a treat! And remember … what must you do with your litter?", "bbox": [258.0, 343.1, 516.0, 444.3], "size": 22.0}]$$),
