    ('lets-have-an-inside-day', 9, $$A tickle tummies and eat gummies day.$$, $$[{"role": "BODY", "text": "A tickle tummies and eat gummies day.", "bbox": [666.1, 254.3, 987.8, 331.3], "size": 35.0}]$$),
