    ('lions-are-always-brave', 0, $$Oh! Hello.$$, $$[{"role": "BODY", "text": "Oh! Hello.", "bbox": [779.5, 509.7, 922.7, 545.7], "size": 36.0}]$$),
    ('lions-are-always-brave', 1, $$I’m a lion. Do you know what that is? Should I tell you? Let me tell you.$$, $$[{"role": "BODY", "text": "I’m a lion. Do you know what that is? Should I tell you? Let me tell you.", "bbox": [97.3, 203.4, 469.6, 369.0], "size": 36.0}]$$),
    ('lions-are-always-brave', 2, $$A lion is strong.$$, $$[{"role": "BODY", "text": "A lion is strong.", "bbox": [740.4, 268.2, 960.4, 304.2], "size": 36.0}]$$),
    ('lions-are-always-brave', 3, $$Lions can run very fast.$$, $$[{"role": "BODY", "text": "Lions can run very fast.", "bbox": [687.0, 268.2, 1013.8, 304.2], "size": 36.0}]$$),
    ('lions-are-always-brave', 4, $$Lions are extreeemely stretchy.$$, $$[{"role": "BODY", "text": "Lions are extreeemely stretchy.", "bbox": [633.7, 507.1, 1067.1, 543.1], "size": 36.0}]$$),
    ('lions-are-always-brave', 5, $$And, um, br ... br ...$$, $$[{"role": "BODY", "text": "And, um, br ... br ...", "bbox": [719.1, 281.7, 981.6, 317.7], "size": 36.0}]$$),
    ('lions-are-always-brave', 6, $$... brave. Lions are always brave! Lions aren’t scared of ...$$, $$[{"role": "BODY", "text": "... brave. Lions are always brave! Lions aren’t scared of ...", "bbox": [87.2, 225.0, 416.3, 347.4], "size": 36.0}]$$),
    ('lions-are-always-brave', 7, $$ANY ... .... THING!$$, $$[{"role": "BODY", "text": "ANY ...", "bbox": [233.6, 509.7, 333.4, 545.7], "size": 36.0}, {"role": "BODY", "text": ".... THING!", "bbox": [772.2, 509.7, 928.6, 545.7], "size": 36.0}]$$),
