    ('little-goat', 0, $$Little Goat went to find the sweetest grass. The sky was blue above. But she did not look up.$$, $$[{"role": "BODY", "text": "Little Goat went to find the sweetest grass.", "bbox": [131.6, 239.7, 435.4, 301.7], "size": 30.0}, {"role": "BODY", "text": "The sky was blue above. But she did not look up.", "bbox": [716.5, 99.8, 984.3, 161.8], "size": 30.0}]$$),
    ('little-goat', 1, $$The river gurgled below. But Little Goat did not listen to its song.$$, $$[{"role": "BODY", "text": "The river gurgled below. But Little Goat did not listen to its song.", "bbox": [629.3, 172.9, 1071.5, 234.9], "size": 30.0}]$$),
    ('little-goat', 2, $$But Little Goat didn’t answer. A bird called to her, saying, “How do you do?”$$, $$[{"role": "BODY", "text": "But Little Goat didn’t answer.", "bbox": [623.6, 105.8, 951.0, 135.8], "size": 30.0}, {"role": "BODY", "text": "A bird called to her, saying, “How do you do?”", "bbox": [57.4, 456.3, 365.3, 518.3], "size": 30.0}]$$),
    ('little-goat', 3, $$Story spread 4 She just walked along looking for the sweetest grass.$$, $$[{"role": "BODY", "text": "Story spread 4", "bbox": [19.1, 35.8, 152.5, 59.8], "size": 24.0}, {"role": "BODY", "text": "She just walked along looking for the sweetest grass.", "bbox": [644.5, 255.7, 1056.2, 317.7], "size": 30.0}]$$),
    ('little-goat', 4, $$As she walked along, Little Goat moved further and further away from Mother Goat.$$, $$[{"role": "BODY", "text": "As she walked along, Little Goat moved further and further away from Mother Goat.", "bbox": [623.6, 171.0, 990.9, 265.0], "size": 30.0}]$$),
    ('little-goat', 5, $$Little Goat found the sweetest grass. She ate and ate. She had walked far from Mother Goat.$$, $$[{"role": "BODY", "text": "Little Goat found the sweetest grass. She ate and ate.", "bbox": [80.2, 58.1, 486.7, 120.1], "size": 30.0}, {"role": "BODY", "text": "She had walked far from Mother Goat.", "bbox": [629.9, 383.8, 1069.5, 413.8], "size": 30.0}]$$),
    ('little-goat', 6, $$Mother Goat wondered where Little Goat had gone. She looked in the mealie patch, but Little Goat was not there.$$, $$[{"role": "BODY", "text": "Mother Goat wondered where Little Goat had gone.", "bbox": [113.5, 231.7, 453.4, 293.7], "size": 30.0}, {"role": "BODY", "text": "She looked in the mealie patch, but Little Goat was not there.", "bbox": [655.2, 455.5, 1053.9, 517.5], "size": 30.0}]$$),
    ('little-goat', 7, $$Mother Goat ran to the river. But Little Goat was not there. “Where are you, Little Goat,” bleated Mother Goat.$$, $$[{"role": "BODY", "text": "Mother Goat ran to the river. But Little Goat was not there.", "bbox": [700.2, 120.9, 1028.9, 182.9], "size": 30.0}, {"role": "BODY", "text": "“Where are you, Little Goat,” bleated Mother Goat.", "bbox": [703.6, 216.9, 1026.6, 278.9], "size": 30.0}]$$),
    ('little-goat', 8, $$A bird called to Mother Goat. “Little Goat is asleep in the sweet grass across the bridge.”$$, $$[{"role": "BODY", "text": "A bird called to Mother Goat. “Little Goat is asleep in the sweet grass across the bridge.”", "bbox": [632.8, 68.3, 1068.0, 162.3], "size": 30.0}]$$),
    ('little-goat', 9, $$Mother Goat crossed the bridge, to the sweet grass.$$, $$[{"role": "BODY", "text": "Mother Goat crossed the bridge, to the sweet grass.", "bbox": [667.1, 255.7, 1033.7, 317.7], "size": 30.0}]$$),
    ('little-goat', 10, $$There she found Little Goat fast asleep.$$, $$[{"role": "BODY", "text": "There she found Little Goat fast asleep.", "bbox": [56.7, 177.8, 364.4, 239.8], "size": 30.0}]$$),
    ('little-goat', 11, $$“Wake up, Little Goat,” said Mother Goat gently. “You were lost!” “I wasn’t lost… I have been here all the time!” said Little Goat.$$, $$[{"role": "BODY", "text": "“Wake up, Little Goat,” said Mother Goat gently. “You were lost!”", "bbox": [56.7, 56.5, 463.6, 118.5], "size": 30.0}, {"role": "BODY", "text": "“I wasn’t lost… I have been here all the time!” said Little Goat.", "bbox": [623.6, 454.9, 1048.8, 516.9], "size": 30.0}]$$),
    ('little-goat', 12, $$$$, $$[]$$),
    ('little-goat', 13, $$$$, $$[]$$),
    ('little-shoots', 0, $$“When will I grow?” asks Layo.$$, $$[{"role": "BODY", "text": "“When will I grow?” asks Layo.", "bbox": [158.1, 89.6, 408.8, 154.7], "size": 30.0}]$$),
    ('little-shoots', 1, $$“I don’t know,” replies Baba. “Soon,” says Mama. “When you are ready,” says Grandma.$$, $$[{"role": "BODY", "text": "“I don’t know,” replies Baba. “Soon,” says Mama.", "bbox": [105.1, 58.5, 461.8, 133.3], "size": 30.0}, {"role": "BODY", "text": "“When you are ready,” says Grandma.", "bbox": [709.2, 59.3, 991.6, 124.5], "size": 30.0}]$$),
    ('little-shoots', 2, $$Grandma takes Layo to the farm. “Let us plant some seeds.”$$, $$[{"role": "BODY", "text": "Grandma takes Layo to the farm. “Let us plant some seeds.”", "bbox": [687.6, 83.0, 1013.2, 185.8], "size": 30.0}]$$),
    ('little-shoots', 3, $$In one field they plant corn, and in another, melon. “What are these?” asks Layo. “Bamboo seeds,” replies Grandma.$$, $$[{"role": "BODY", "text": "In one field they plant corn, and in another, melon.", "bbox": [103.9, 116.5, 463.0, 182.5], "size": 30.0}, {"role": "BODY", "text": "“What are these?” asks Layo. “Bamboo seeds,” replies Grandma.", "bbox": [631.5, 116.5, 1069.3, 191.4], "size": 30.0}]$$),
    ('little-shoots', 4, $$$$, $$[]$$),
    ('little-shoots', 5, $$“The corn and melon have grown well,” says Grandma. “What about the bamboo?” asks Layo. “They will grow when they are ready.”$$, $$[{"role": "BODY", "text": "“The corn and melon have grown well,” says Grandma. “What about the bamboo?” asks Layo.", "bbox": [74.8, 59.1, 492.1, 216.3], "size": 30.0}, {"role": "BODY", "text": "“They will grow when they are ready.”", "bbox": [659.4, 59.1, 1041.4, 125.1], "size": 30.0}]$$),
    ('little-shoots', 6, $$$$, $$[]$$),
    ('little-shoots', 7, $$“Everything grows in its own time,” says Grandma.$$, $$[{"role": "BODY", "text": "“Everything grows in its own time,” says Grandma.", "bbox": [63.0, 61.0, 504.0, 126.1], "size": 30.0}]$$),
    ('little-shoots', 8, $$$$, $$[]$$),
    ('little-shoots', 9, $$“They have grown well,” says Grandma.$$, $$[{"role": "BODY", "text": "“They have grown well,” says Grandma.", "bbox": [132.2, 254.4, 434.8, 319.6], "size": 30.0}]$$),
    ('little-shoots', 10, $$$$, $$[]$$),
    ('little-shoots', 11, $$“You have grown well.”$$, $$[{"role": "BODY", "text": "“You have grown well.”", "bbox": [696.5, 96.1, 1004.3, 128.1], "size": 32.0}]$$),
    ('little-shoots', 12, $$$$, $$[]$$),
    ('little-shoots', 13, $$$$, $$[]$$),
    ('lonwabos-recipes', 0, $$Lonwabo was a ten-year-old boy. He lived with his mother and grandmother.$$, $$[{"role": "BODY", "text": "Lonwabo was a ten-year-old boy.", "bbox": [197.9, 113.9, 502.2, 137.9], "size": 24.0}, {"role": "BODY", "text": "He lived with his mother and grandmother.", "bbox": [623.6, 113.9, 839.2, 166.7], "size": 24.0}]$$),
    ('lonwabos-recipes', 1, $$Lonwabo’s grandmother had the most beautiful and rich vegetable garden. He enjoyed helping his grandmother weed the garden and water the vegetables.$$, $$[{"role": "BODY", "text": "Lonwabo’s grandmother had the most beautiful and rich vegetable garden.", "bbox": [247.3, 56.3, 510.2, 137.9], "size": 24.0}, {"role": "BODY", "text": "He enjoyed helping his grandmother weed the garden and water the vegetables.", "bbox": [623.6, 56.3, 899.1, 137.9], "size": 24.0}]$$),
    ('lonwabos-recipes', 2, $$He had to fetch water from the river. He was not a lazy boy. He would walk down the hill and up again. He would pass his friends playing soccer and they would laugh out loud and say to him, “Lonwabo why do you do that? That is a girl’s job, we would never do that.”$$, $$[{"role": "BODY", "text": "He had to fetch water from the river. He was not a lazy boy. He would walk down the hill and up again.", "bbox": [83.3, 113.9, 483.7, 195.5], "size": 24.0}, {"role": "BODY", "text": "He would pass his friends playing soccer and they would laugh out loud and say to him, “Lonwabo why do you do that? That is a girl’s job, we would never do that.”", "bbox": [624.2, 113.9, 1076.6, 224.3], "size": 24.0}]$$),
    ('lonwabos-recipes', 3, $$Lonwabo laughed them off and continued with his journey. He would think about all the happy times with his grandmother in the garden.$$, $$[{"role": "BODY", "text": "Lonwabo laughed them off and continued with his journey.", "bbox": [92.3, 142.7, 474.6, 195.5], "size": 24.0}, {"role": "BODY", "text": "He would think about all the happy times with his grandmother in the garden.", "bbox": [62.5, 229.1, 504.4, 281.9], "size": 24.0}]$$),
    ('lonwabos-recipes', 4, $$These thoughts made him forget about the long journey and about his friends’ comments. He liked guessing how many carrots would be in each bunch before his grandmother pulled them out of the ground.$$, $$[{"role": "BODY", "text": "These thoughts made him forget about the long journey and about his friends’ comments.", "bbox": [206.5, 257.9, 510.7, 339.5], "size": 24.0}, {"role": "BODY", "text": "He liked guessing how many carrots would be in each bunch before his grandmother pulled them out of the ground.", "bbox": [230.1, 373.1, 510.8, 483.5], "size": 24.0}]$$),
    ('lonwabos-recipes', 5, $$$$, $$[]$$),
    ('lonwabos-recipes', 6, $$Lonwabo’s grandmother always prepared lunch for him, while he was at school and his mother was at work. Every day he came home to find his food already prepared and left out on the table for him.$$, $$[{"role": "BODY", "text": "Lonwabo’s grandmother always prepared lunch for him, while he was at school and his mother was at work.", "bbox": [56.9, 171.5, 510.0, 253.1], "size": 24.0}, {"role": "BODY", "text": "Every day he came home to find his food already prepared and left out on the table for him.", "bbox": [61.0, 286.7, 506.5, 368.3], "size": 24.0}]$$),
    ('lonwabos-recipes', 7, $$Immediately after taking off his school uniform, he sat at the table, said a little prayer and began to eat.$$, $$[{"role": "BODY", "text": "Immediately after taking off his school uniform, he sat at the table, said a little prayer and began to eat.", "bbox": [62.8, 229.1, 504.2, 310.7], "size": 24.0}]$$),
    ('lonwabos-recipes', 8, $$His grandmother prepared all kinds of meals for their lunches. He loved his grandmother’s tasty meals.$$, $$[{"role": "BODY", "text": "His grandmother prepared all kinds of meals for their lunches.", "bbox": [112.4, 257.9, 455.0, 310.7], "size": 24.0}, {"role": "BODY", "text": "He loved his grandmother’s tasty meals.", "bbox": [671.6, 257.9, 1029.2, 281.9], "size": 24.0}]$$),
    ('lonwabos-recipes', 9, $$When he finished eating, he would wash his dish, take a book and pencil and go and sit next to his grandmother. He asked her about the ingredients in the meal he had just eaten and carefully wrote down every little detail.$$, $$[{"role": "BODY", "text": "When he finished eating, he would wash his dish, take a book and pencil and go and sit next to his grandmother.", "bbox": [654.3, 113.9, 1046.5, 195.5], "size": 24.0}, {"role": "BODY", "text": "He asked her about the ingredients in the meal he had just eaten and carefully wrote down every little detail.", "bbox": [630.6, 229.1, 1070.8, 310.7], "size": 24.0}]$$),
    ('lonwabos-recipes', 10, $$He told himself that when grows up, he is going to open his own restaurant. He will name the restaurant after his grandmother and make all the meals that his grandmother makes for him.$$, $$[{"role": "BODY", "text": "He told himself that when grows up, he is going to open his own restaurant.", "bbox": [111.5, 113.9, 455.5, 166.7], "size": 24.0}, {"role": "BODY", "text": "He will name the restaurant after his grandmother and make all the meals that his grandmother makes for him.", "bbox": [626.8, 113.9, 1074.5, 195.5], "size": 24.0}]$$),
    ('lonwabos-recipes', 11, $$$$, $$[]$$),
    ('lonwabos-recipes', 12, $$$$, $$[]$$),
    ('lonwabos-recipes', 13, $$$$, $$[]$$),
    ('look-out-luthando', 0, $$“Listen!” says Luthando. “What do you hear?” asks Sonto. “Saturday.” “What does Saturday sound like?” “It’s quieter than Friday,” says Luthando. “Everyone’s still sleeping.”$$, $$[{"role": "BODY", "text": "“Listen!” says Luthando. “What do you hear?” asks Sonto. “Saturday.” “What does Saturday sound like?” “It’s quieter than Friday,” says Luthando. “Everyone’s still sleeping.”", "bbox": [75.2, 196.2, 491.7, 350.2], "size": 22.0}]$$),
    ('look-out-luthando', 1, $$“I must fix Gogo’s gate today,” Daddy says. “An ice cream for anyone who helps me carry the shopping home,” Mama says. “We’ll help you, Mama,” say the children.$$, $$[{"role": "BODY", "text": "“I must fix Gogo’s gate today,” Daddy says.", "bbox": [60.9, 61.6, 506.0, 83.6], "size": 22.0}, {"role": "BODY", "text": "“An ice cream for anyone who helps me carry the shopping home,” Mama says. “We’ll help you, Mama,” say the children.", "bbox": [614.5, 61.6, 1086.3, 136.4], "size": 22.0}]$$),
    ('look-out-luthando', 2, $$“Look out, Luthando!” “Hawu!” “You’re so funny,” Sonto laughs.$$, $$[{"role": "BODY", "text": "“Look out, Luthando!” “Hawu!” “You’re so funny,” Sonto laughs.", "bbox": [120.7, 440.7, 446.2, 515.5], "size": 22.0}]$$),
    ('look-out-luthando', 3, $$“I hear a motorbike,” says Luthando. “There’s no motorbike,” says Sonto, looking all around.$$, $$[{"role": "BODY", "text": "“I hear a motorbike,” says Luthando.", "bbox": [95.9, 61.6, 471.0, 83.6], "size": 22.0}, {"role": "BODY", "text": "“There’s no motorbike,” says Sonto, looking all around.", "bbox": [636.5, 61.6, 1002.0, 110.0], "size": 22.0}]$$),
    ('look-out-luthando', 4, $$A motorbike zooms past. “You’re very good at hearing, Luthando.”$$, $$[{"role": "BODY", "text": "A motorbike zooms past. “You’re very good at hearing, Luthando.”", "bbox": [168.1, 85.7, 424.4, 160.5], "size": 22.0}]$$),
    ('look-out-luthando', 5, $$“Look out, Luthando!” “Hawu!” says Luthando as he steps into a puddle. “Look how wet you are,” says Mama.$$, $$[{"role": "BODY", "text": "“Look out, Luthando!” “Hawu!” says Luthando as he steps into a puddle.", "bbox": [54.7, 61.6, 322.3, 136.4], "size": 22.0}, {"role": "BODY", "text": "“Look how wet you are,” says Mama.", "bbox": [690.7, 61.6, 940.6, 110.0], "size": 22.0}]$$),
    ('look-out-luthando', 6, $$“Daddy’s home.” “How do you know, Luthando?” asks Sonto. “I can smell his cooking,” says Luthando sniffing the air. “You’re also good at smelling,” Mama says.$$, $$[{"role": "BODY", "text": "“Daddy’s home.” “How do you know, Luthando?” asks Sonto.", "bbox": [60.9, 61.6, 506.0, 110.0], "size": 22.0}, {"role": "BODY", "text": "“I can smell his cooking,” says Luthando sniffing the air. “You’re also good at smelling,” Mama says.", "bbox": [629.5, 394.3, 1071.3, 469.1], "size": 22.0}]$$),
    ('look-out-luthando', 7, $$“Look out, Luthando!” “Ouch!” “Watch where you’re walking,” Mama says. “Luthando’s not so good at looking,” says Sonto.$$, $$[{"role": "BODY", "text": "“Look out, Luthando!” “Ouch!” “Watch where you’re walking,” Mama says. “Luthando’s not so good at looking,” says Sonto.", "bbox": [94.2, 41.7, 518.4, 169.3], "size": 22.0}]$$),
    ('look-out-luthando', 8, $$“What do you see, Luthando?” asks the friendly woman. Luthando squeezes his eyes together. He sees black squiggles on the wall. He looks through a pair of glasses. “I see letters,” he says. “Excellent!”$$, $$[{"role": "BODY", "text": "“What do you see, Luthando?” asks the friendly woman. Luthando squeezes his eyes together. He sees black squiggles on the wall.", "bbox": [90.8, 57.3, 476.1, 158.5], "size": 22.0}, {"role": "BODY", "text": "He looks through a pair of glasses. “I see letters,” he says. “Excellent!”", "bbox": [671.6, 61.6, 1029.2, 136.4], "size": 22.0}]$$),
    ('look-out-luthando', 9, $$“Look, Gogo!” “You have glasses,” says Gogo, clapping her hands. “How wonderful. Tell me what you see.” “I see bugs and ants and spiders and bees. I see EVERYTHING now.”$$, $$[{"role": "BODY", "text": "“Look, Gogo!” “You have glasses,” says Gogo, clapping her hands. “How wonderful. Tell me what you see.”", "bbox": [81.3, 47.4, 485.7, 148.6], "size": 22.0}, {"role": "BODY", "text": "“I see bugs and ants and spiders and bees. I see EVERYTHING now.”", "bbox": [630.0, 47.4, 1070.8, 95.8], "size": 22.0}]$$),
    ('look-out-luthando', 10, $$“Gogo, your face has cracks,” says Luthando, touching Gogo’s face. “Hayi…Luthando! Those aren’t cracks. They’re lines on my face from getting old and laughing at all the funny things you say.”$$, $$[{"role": "BODY", "text": "“Gogo, your face has cracks,” says Luthando, touching Gogo’s face. “Hayi…Luthando! Those aren’t cracks. They’re lines on my face from getting old and laughing at all the funny things you say.”", "bbox": [614.2, 186.3, 1086.6, 313.9], "size": 22.0}]$$),
    ('look-out-luthando', 11, $$“Don’t...” “Look, a puddle!” says Luthando. Too late!$$, $$[{"role": "BODY", "text": "“Don’t...”", "bbox": [240.7, 61.6, 326.2, 83.6], "size": 22.0}, {"role": "BODY", "text": "“Look, a puddle!” says Luthando.", "bbox": [682.5, 61.6, 1018.3, 83.6], "size": 22.0}, {"role": "BODY", "text": "Too late!", "bbox": [652.4, 424.8, 765.6, 451.8], "size": 27.0}]$$),
    ('look-out-luthando', 12, $$$$, $$[]$$),
    ('look-out-luthando', 13, $$$$, $$[]$$),
    ('look-up', 0, $$Wow, look up! What do you see?$$, $$[{"role": "BODY", "text": "Wow, look up! What do you see?", "bbox": [56.7, 63.9, 257.4, 123.9], "size": 25.0}]$$),
    ('look-up', 1, $$Story spread 2 In the morning ... Small sparrows and big hadedas.$$, $$[{"role": "BODY", "text": "Story spread 2", "bbox": [-142.4, -122.4, 19.7, -98.4], "size": 24.0}, {"role": "BODY", "text": "In the morning ...", "bbox": [56.7, 63.9, 248.7, 88.9], "size": 25.0}, {"role": "BODY", "text": "Small sparrows and big hadedas.", "bbox": [623.6, 63.9, 1006.1, 88.9], "size": 25.0}]$$),
    ('look-up', 2, $$In the daytime ... A flutter of butterflies over flowers.$$, $$[{"role": "BODY", "text": "In the daytime ...", "bbox": [56.7, 63.9, 244.8, 88.9], "size": 25.0}, {"role": "BODY", "text": "A flutter of butterflies over flowers.", "bbox": [623.6, 63.9, 1026.1, 88.9], "size": 25.0}]$$),
    ('look-up', 3, $$A sugarbird with its long tail. A sunbird with its bright red collar.$$, $$[{"role": "BODY", "text": "A sugarbird with its long tail.", "bbox": [56.7, 63.9, 394.2, 88.9], "size": 25.0}, {"role": "BODY", "text": "A sunbird with its bright red collar.", "bbox": [623.6, 156.1, 1028.0, 181.1], "size": 25.0}]$$),
    ('look-up', 4, $$A yellow-billed kite soaring high in the sky.$$, $$[{"role": "BODY", "text": "A yellow-billed kite soaring high in the sky.", "bbox": [56.7, 63.9, 321.2, 123.9], "size": 25.0}]$$),
    ('look-up', 5, $$In the late afternoon ... Bees buzzing to their hive.$$, $$[{"role": "BODY", "text": "In the late afternoon ... Bees buzzing to their hive.", "bbox": [623.6, 63.9, 923.4, 123.9], "size": 25.0}]$$),
    ('look-up', 6, $$As the sun sets ... Geese flying home.$$, $$[{"role": "BODY", "text": "As the sun sets ...", "bbox": [56.7, 63.9, 250.2, 88.9], "size": 25.0}, {"role": "BODY", "text": "Geese flying home.", "bbox": [623.6, 63.9, 839.7, 88.9], "size": 25.0}]$$),
    ('look-up', 7, $$The twinkling lights of an aeroplane full of people.$$, $$[{"role": "BODY", "text": "The twinkling lights of an aeroplane full of people.", "bbox": [623.6, 402.4, 968.2, 462.4], "size": 25.0}]$$),
    ('look-up', 8, $$Bats eating insects for their dinner.$$, $$[{"role": "BODY", "text": "Bats eating insects for their dinner.", "bbox": [623.6, 424.6, 1022.9, 449.6], "size": 25.0}]$$),
    ('look-up', 9, $$When it’s nice and dark ... An owl swooping over a field.$$, $$[{"role": "BODY", "text": "When it’s nice and dark ... An owl swooping over a field.", "bbox": [623.6, 396.7, 962.4, 456.7], "size": 25.0}]$$),
    ('look-up', 10, $$A shooting star.$$, $$[{"role": "BODY", "text": "A shooting star.", "bbox": [623.6, 481.3, 803.0, 506.3], "size": 25.0}]$$),
    ('look-up', 11, $$Even when we’re dreaming there is so much to see!$$, $$[{"role": "BODY", "text": "Even when we’re dreaming there is so much to see!", "bbox": [56.7, 63.9, 365.6, 123.9], "size": 25.0}]$$),
    ('look-up', 12, $$$$, $$[]$$),
