    ('malis-friend', 0, $$Mali enjoys playing by himself. He likes to be a pilot, swooshing around the house with his paper plane. Swoosh! Swoosh! Swoosh! Then a taxi driver, hooting around the yard with his wire car. Beep! Beep! Beeeeeeeeeeep! Mali never goes out to play with others.$$, $$[{"role": "BODY", "text": "Mali enjoys playing by himself.", "bbox": [279.2, 167.8, 484.4, 211.8], "size": 20.0}, {"role": "BODY", "text": "He likes to be a pilot, swooshing around the house with his paper plane.", "bbox": [279.2, 239.8, 482.8, 331.8], "size": 20.0}, {"role": "BODY", "text": "Swoosh! Swoosh! Swoosh!", "bbox": [279.2, 363.6, 474.5, 416.4], "size": 24.0}, {"role": "BODY", "text": "Then a taxi driver, hooting around the yard with his wire car.", "bbox": [623.6, 110.6, 935.4, 154.6], "size": 20.0}, {"role": "BODY", "text": "Beep! Beep! Beeeeeeeeeeep!", "bbox": [623.6, 210.4, 813.8, 263.2], "size": 24.0}, {"role": "BODY", "text": "Mali never goes out to play with others.", "bbox": [623.6, 321.8, 803.8, 365.8], "size": 20.0}]$$),
    ('malis-friend', 1, $$Gogo says, “Mali go out and play ibhola with the others.” But Mali does not enjoy himself.$$, $$[{"role": "BODY", "text": "Gogo says,", "bbox": [623.6, 78.3, 724.5, 98.3], "size": 20.0}, {"role": "BODY", "text": "“Mali go out and play ibhola with the others.”", "bbox": [755.0, 158.2, 1008.2, 213.1], "size": 24.0}, {"role": "BODY", "text": "But Mali does not enjoy himself.", "bbox": [895.8, 400.4, 1055.5, 444.4], "size": 20.0}]$$),
    ('malis-friend', 2, $$Gogo says, “Mali, look, the children are playing ibhathi. Go out and play.” Mali tries again. But he does not enjoy himself.$$, $$[{"role": "BODY", "text": "Gogo says,", "bbox": [113.4, 80.4, 214.3, 100.4], "size": 20.0}, {"role": "BODY", "text": "“Mali, look, the children are playing ibhathi. Go out and play.”", "bbox": [126.9, 216.8, 377.7, 298.4], "size": 24.0}, {"role": "BODY", "text": "Mali tries again. But he does not enjoy himself.", "bbox": [831.3, 435.1, 1042.7, 479.1], "size": 20.0}]$$),
    ('malis-friend', 3, $$Gogo tries one more time. “Mali, go out and play maphonselana with the others.” Once again, Mali tries. He does not enjoy himself.$$, $$[{"role": "BODY", "text": "Gogo tries one more time.", "bbox": [623.6, 72.3, 861.6, 92.3], "size": 20.0}, {"role": "BODY", "text": "“Mali, go out and play maphonselana with the others.”", "bbox": [691.6, 173.4, 917.2, 255.0], "size": 24.0}, {"role": "BODY", "text": "Once again, Mali tries. He does not enjoy himself.", "bbox": [623.6, 411.1, 866.1, 455.1], "size": 20.0}]$$),
    ('malis-friend', 4, $$There is a knock on the door. Ko! Ko! Ko! It’s Lesedi from next door. She has come to play. Mali is shy. He does not know how to play with Lesedi. Lesedi asks him if he would like to make mud pies and cakes.$$, $$[{"role": "BODY", "text": "There is a knock on the door.", "bbox": [56.7, 83.4, 321.0, 103.4], "size": 20.0}, {"role": "BODY", "text": "Ko! Ko! Ko!", "bbox": [56.7, 135.2, 179.2, 159.2], "size": 24.0}, {"role": "BODY", "text": "It’s Lesedi from next door. She has come to play.", "bbox": [840.5, 169.8, 1075.4, 213.8], "size": 20.0}, {"role": "BODY", "text": "Mali is shy. He does not know how to play with Lesedi.", "bbox": [840.5, 241.8, 1054.7, 309.8], "size": 20.0}, {"role": "BODY", "text": "Lesedi asks him if he would like to make mud pies and cakes.", "bbox": [840.5, 337.8, 1059.2, 405.8], "size": 20.0}]$$),
    ('malis-friend', 5, $$They make mud pies and cakes and even pancakes and biscuits. Mali enjoys himself very much.$$, $$[{"role": "BODY", "text": "They make mud pies and cakes and even pancakes and biscuits.", "bbox": [56.7, 159.5, 263.8, 227.5], "size": 20.0}, {"role": "BODY", "text": "Mali enjoys himself very much.", "bbox": [936.9, 159.5, 1049.0, 227.5], "size": 20.0}]$$),
    ('malis-friend', 6, $$Lesedi comes back again. She shows Mali how to play ingedo. Mali has trouble throwing, moving and catching the stones. But he gets better at the game. Mali enjoys himself very much.$$, $$[{"role": "BODY", "text": "Lesedi comes back again. She shows Mali how to play ingedo.", "bbox": [68.0, 125.6, 207.1, 243.4], "size": 20.0}, {"role": "BODY", "text": "Mali has trouble throwing, moving and catching the stones. But he gets better at the game.", "bbox": [677.5, 78.8, 1011.0, 146.8], "size": 20.0}, {"role": "BODY", "text": "Mali enjoys himself very much.", "bbox": [887.6, 436.6, 1062.0, 480.6], "size": 20.0}]$$),
    ('malis-friend', 7, $$Mali then shows Lesedi how to make a paper plane. They go all around the house swooshing their planes. Oh! They laugh a lot!$$, $$[{"role": "BODY", "text": "Mali then shows Lesedi how to make a paper plane.", "bbox": [623.6, 205.8, 901.4, 249.8], "size": 20.0}, {"role": "BODY", "text": "They go all around the house swooshing their planes.", "bbox": [623.6, 277.8, 892.5, 321.8], "size": 20.0}, {"role": "BODY", "text": "Oh! They laugh a lot!", "bbox": [623.6, 349.8, 811.9, 369.8], "size": 20.0}]$$),
    ('malis-friend', 8, $$Mali asks Lesedi, “Can I come to your house to play tomorrow?” “Of course you can!” she laughs.$$, $$[{"role": "BODY", "text": "Mali asks Lesedi,", "bbox": [56.7, 90.7, 208.9, 110.7], "size": 20.0}, {"role": "BODY", "text": "“Can I come to your house to play tomorrow?”", "bbox": [363.6, 151.0, 492.4, 290.2], "size": 24.0}, {"role": "BODY", "text": "“Of course you can!”", "bbox": [652.1, 167.3, 768.0, 220.1], "size": 24.0}, {"role": "BODY", "text": "she laughs.", "bbox": [728.9, 418.1, 830.5, 438.1], "size": 20.0}]$$),
    ('malis-friend', 9, $$The next morning, after gobbling down his porridge, Mali takes out his wire car.$$, $$[{"role": "BODY", "text": "The next morning, after gobbling down his porridge, Mali takes out his wire car.", "bbox": [623.6, 197.0, 1013.4, 241.0], "size": 20.0}]$$),
    ('malis-friend', 10, $$“Where are you going, Mali?” asks Gogo.$$, $$[{"role": "BODY", "text": "“Where are you going, Mali?”", "bbox": [181.1, 159.6, 352.8, 212.4], "size": 24.0}, {"role": "BODY", "text": "asks Gogo.", "bbox": [368.5, 328.7, 468.6, 348.7], "size": 20.0}]$$),
    ('malis-friend', 11, $$“I am going out to play with Lesedi!” he laughs.$$, $$[{"role": "BODY", "text": "“I am going out to play with Lesedi!”", "bbox": [278.1, 104.2, 476.0, 157.0], "size": 24.0}, {"role": "BODY", "text": "he laughs.", "bbox": [417.9, 287.6, 510.2, 307.6], "size": 20.0}]$$),
    ('malis-friend', 12, $$$$, $$[]$$),
    ('malis-friend', 13, $$$$, $$[]$$),
    ('mama-antelopes-house', 0, $$Long ago, all the animals lived in a village. Mama Antelope had a big house.$$, $$[{"role": "BODY", "text": "Long ago, all the animals lived in a village. Mama Antelope had a big house.", "bbox": [72.9, 452.2, 494.0, 509.2], "size": 20.0}]$$),
    ('mama-antelopes-house', 1, $$One day, Hare wanted to play a trick. He thought and thought and thought… He crept into Mama Antelope’s house. He closed the door and made a lot of noise.$$, $$[{"role": "BODY", "text": "One day, Hare wanted to play a trick. He thought and thought and thought… He crept into Mama Antelope’s house. He closed the door and made a lot of noise.", "bbox": [66.6, 122.0, 501.8, 253.0], "size": 20.0}]$$),
    ('mama-antelopes-house', 2, $$Mama Antelope came home. “Who is in my house?” she cried. Someone “Hyena, is please in my help! house.” PING! CLINK!$$, $$[{"role": "BODY", "text": "Mama Antelope came home. “Who is in my house?” she cried.", "bbox": [124.0, 196.4, 442.9, 253.4], "size": 20.0}, {"role": "BODY", "text": "Someone “Hyena, is please in my help! house.”", "bbox": [160.6, 307.4, 412.6, 364.4], "size": 20.0}, {"role": "SFX", "text": "PING!", "bbox": [903.3, 68.2, 1018.0, 144.5], "size": 48.9}, {"role": "SFX", "text": "CLINK!", "bbox": [940.6, 305.1, 1078.7, 389.4], "size": 48.8}]$$),
    ('mama-antelopes-house', 3, $$Knock, knock, knock! “Open the door!” howled Hyena. But the door did not open. CRASH! SNAP!$$, $$[{"role": "BODY", "text": "Knock, knock, knock! “Open the door!” howled Hyena. But the door did not open.", "bbox": [125.8, 94.3, 441.2, 188.3], "size": 20.0}, {"role": "SFX", "text": "CRASH!", "bbox": [670.7, 184.6, 841.5, 245.7], "size": 48.8}, {"role": "SFX", "text": "SNAP!", "bbox": [890.3, 240.7, 1032.8, 315.5], "size": 52.3}]$$),
    ('mama-antelopes-house', 4, $$Hyena called Giraffe. “Open the door!” shouted Giraffe. BANG! SMASH! But the door did not open.$$, $$[{"role": "BODY", "text": "Hyena called Giraffe. “Open the door!” shouted Giraffe.", "bbox": [137.5, 301.2, 345.8, 395.2], "size": 20.0}, {"role": "SFX", "text": "BANG!", "bbox": [604.3, 255.5, 752.6, 345.4], "size": 54.5}, {"role": "SFX", "text": "SMASH!", "bbox": [930.9, 248.1, 1111.0, 310.1], "size": 49.2}, {"role": "BODY", "text": "But the door did not open.", "bbox": [621.1, 497.6, 881.2, 517.5], "size": 20.0}]$$),
    ('mama-antelopes-house', 5, $$Giraffe called Zebra. “Open the door!” yelled Zebra. But the door did not open. BASH! BOOM!$$, $$[{"role": "BODY", "text": "Giraffe called Zebra. “Open the door!” yelled Zebra. But the door did not open.", "bbox": [52.6, 124.3, 351.8, 218.3], "size": 20.0}, {"role": "SFX", "text": "BASH! BOOM!", "bbox": [871.5, 201.0, 1106.9, 393.6], "size": 54.0}]$$),
    ('mama-antelopes-house', 6, $$Zebra called Elephant. He “Open was big the and door!” strong. commanded But the door Elephant. did not open. BOOM! BOOM! BOOM!$$, $$[{"role": "BODY", "text": "Zebra called Elephant. He “Open was big the and door!” strong. commanded But the door Elephant. did not open.", "bbox": [58.9, 61.0, 286.9, 266.0], "size": 20.0}, {"role": "SFX", "text": "BOOM! BOOM! BOOM!", "bbox": [872.5, 83.6, 1107.5, 312.7], "size": 53.5}]$$),
    ('mama-antelopes-house', 7, $$Mama Antelope was sad. All the animals were sad. Who was in Mama Antelope’s house?$$, $$[{"role": "BODY", "text": "Mama Antelope was sad. All the animals were sad.", "bbox": [726.6, 224.0, 974.2, 281.0], "size": 20.0}, {"role": "BODY", "text": "Who was in Mama Antelope’s house?", "bbox": [667.1, 335.0, 1033.7, 355.0], "size": 20.0}]$$),
    ('mama-antelopes-house', 8, $$The birds sang. The butterflies flapped. The bees buzzed. “Open the door!” they all cried.$$, $$[{"role": "BODY", "text": "The birds sang. The butterflies flapped. The bees buzzed. “Open the door!” they all cried.", "bbox": [131.8, 209.8, 435.2, 340.8], "size": 20.0}]$$),
    ('mama-antelopes-house', 9, $$Baby Antelope came home. “Who is in our house?” “Please open the door,” she asked sweetly.$$, $$[{"role": "BODY", "text": "Baby Antelope came home. “Who is in our house?”", "bbox": [147.0, 81.6, 419.9, 138.6], "size": 20.0}, {"role": "BODY", "text": "“Please open the door,” she asked sweetly.", "bbox": [167.8, 192.6, 399.1, 249.6], "size": 20.0}]$$),
    ('mama-antelopes-house', 10, $$The door opened. It was Hare! Hare was smiling. He loved tricks.$$, $$[{"role": "BODY", "text": "The door opened. It was Hare! Hare was smiling. He loved tricks.", "bbox": [92.3, 107.1, 266.7, 238.1], "size": 20.0}]$$),
    ('mama-antelopes-house', 11, $$Hurrah! Hurrah! Mama Antelope and Baby Antelope are happy. The animals are happy. Mama Antelope’s house is open at last.$$, $$[{"role": "BODY", "text": "Hurrah! Hurrah! Mama Antelope and Baby Antelope are happy. The animals are happy. Mama Antelope’s house is open at last.", "bbox": [90.0, 336.0, 476.9, 504.0], "size": 20.0}]$$),
    ('mama-antelopes-house', 12, $$$$, $$[]$$),
    ('mama-antelopes-house', 13, $$$$, $$[]$$),
    ('mama-whats-for-lunch', 0, $$“Hurry,Thabo. Mama is making lunch,” calls Tumi.$$, $$[{"role": "BODY", "text": "“Hurry,Thabo. Mama is making lunch,” calls Tumi.", "bbox": [623.6, 474.9, 982.8, 518.9], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 1, $$“Where are you going, Thabo?”$$, $$[{"role": "BODY", "text": "“Where are you going, Thabo?”", "bbox": [664.7, 82.4, 985.4, 104.4], "size": 22.0}]$$),
    ('mama-whats-for-lunch', 2, $$His friends don’t understand why he chooses lunch over their game, but Thabo has a secret. Mama’s lunches are special.$$, $$[{"role": "BODY", "text": "His friends don’t understand why he chooses lunch over their game, but Thabo has a secret.", "bbox": [56.7, 443.0, 486.9, 487.0], "size": 20.0}, {"role": "BODY", "text": "Mama’s lunches are special.", "bbox": [623.6, 449.3, 881.9, 469.3], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 3, $$On Monday, Mama shapes their food like little bugs that wriggle and crawl, making Tumi shriek in fright. “EEEE!” But they are yummy fruit and vegetables, and not very scary at all.$$, $$[{"role": "BODY", "text": "On Monday, Mama shapes their food like little bugs that wriggle and crawl, making Tumi shriek in fright.", "bbox": [623.6, 78.0, 1070.2, 146.0], "size": 20.0}, {"role": "SFX", "text": "“EEEE!”", "bbox": [623.6, 180.1, 725.6, 208.1], "size": 28.0}, {"role": "BODY", "text": "But they are yummy fruit and vegetables, and not very scary at all.", "bbox": [623.6, 241.2, 1045.8, 294.8], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 4, $$On Tuesday, she makes a lion that roars so loudly the house shakes. “ROAR!” But it’s just delicious pasta and cheese.$$, $$[{"role": "BODY", "text": "On Tuesday, she makes a lion that roars so loudly the house shakes.", "bbox": [623.6, 84.3, 1057.7, 126.1], "size": 19.0}, {"role": "BODY", "text": "“ROAR!” But it’s just delicious pasta and cheese.", "bbox": [623.6, 182.3, 987.7, 253.9], "size": 24.0}]$$),
    ('mama-whats-for-lunch', 5, $$On Wednesday, Mama creates a chicken that wakes up the whole street. “CLUCK CLUCK PAKAA!” But it’s just a plate of juicy fruit.$$, $$[{"role": "BODY", "text": "On Wednesday, Mama creates a chicken that wakes up the whole street.", "bbox": [623.6, 78.7, 1040.6, 122.7], "size": 20.0}, {"role": "SFX", "text": "“CLUCK CLUCK PAKAA!”", "bbox": [623.6, 156.8, 947.6, 184.8], "size": 28.0}, {"role": "BODY", "text": "But it’s just a plate of juicy fruit.", "bbox": [623.6, 217.9, 924.5, 237.9], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 6, $$On Thursday, she builds a noisy truck. Thabo and Tumi cover their ears. “VROOOM!” But it’s a sweet strawberry jam sandwich.$$, $$[{"role": "BODY", "text": "On Thursday, she builds a noisy truck.", "bbox": [623.6, 80.1, 975.4, 100.1], "size": 20.0}, {"role": "BODY", "text": "Thabo and Tumi cover their ears.", "bbox": [623.6, 128.1, 930.2, 148.1], "size": 20.0}, {"role": "SFX", "text": "“VROOOM!”", "bbox": [623.6, 183.7, 794.6, 213.7], "size": 30.0}, {"role": "BODY", "text": "But it’s a sweet strawberry jam sandwich.", "bbox": [623.6, 248.1, 1010.1, 268.1], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 7, $$On Friday, Mama makes a beautiful garden filled with flowers, birds and ladybugs. “TWEET TWEET!” But it’s healthy pap, beans and a crunchy salad.$$, $$[{"role": "BODY", "text": "On Friday, Mama makes a beautiful garden filled with flowers, birds and ladybugs.", "bbox": [625.0, 79.4, 1072.1, 123.4], "size": 20.0}, {"role": "BODY", "text": "“TWEET TWEET!” But it’s healthy pap, beans and a crunchy salad.", "bbox": [625.0, 157.5, 1067.0, 229.0], "size": 24.0}, {"role": "DECOR", "text": "PAP", "bbox": [955.8, 407.3, 997.0, 428.3], "size": 21.0}]$$),
    ('mama-whats-for-lunch', 8, $$“Mama, what’s for lunch?” asks Tumi. “Yes, Mama,” says Thabo. “What are you making today?”$$, $$[{"role": "BODY", "text": "“Mama, what’s for lunch?” asks Tumi.", "bbox": [623.6, 78.0, 974.1, 98.0], "size": 20.0}, {"role": "BODY", "text": "“Yes, Mama,” says Thabo. “What are you making today?”", "bbox": [623.6, 126.0, 1007.6, 170.0], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 9, $$Thabo and Tumi can’t wait another second. Their tummies are grumbling. Finally, Mama is ready. “What is it Mama?” asks Thabo, licking his lips.$$, $$[{"role": "BODY", "text": "Thabo and Tumi can’t wait another second. Their tummies are grumbling.", "bbox": [623.6, 203.4, 1023.8, 247.4], "size": 20.0}, {"role": "BODY", "text": "Finally, Mama is ready.", "bbox": [623.6, 275.4, 837.4, 295.4], "size": 20.0}, {"role": "BODY", "text": "“What is it Mama?” asks Thabo, licking his lips.", "bbox": [623.6, 323.4, 1061.1, 343.4], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 10, $$It’s Thabo, Tumi and Mama! “Mmm, our favourite, your famous stew and rice.” “Thank you, Mama!”$$, $$[{"role": "BODY", "text": "It’s Thabo, Tumi and Mama!", "bbox": [623.6, 80.8, 885.7, 100.8], "size": 20.0}, {"role": "BODY", "text": "“Mmm, our favourite, your famous stew and rice.”", "bbox": [623.6, 152.8, 1032.3, 196.8], "size": 20.0}, {"role": "BODY", "text": "“Thank you, Mama!”", "bbox": [623.6, 224.8, 814.6, 244.8], "size": 20.0}]$$),
    ('mama-whats-for-lunch', 11, $$What will Mama make on Sunday?$$, $$[{"role": "BODY", "text": "What will Mama make on Sunday?", "bbox": [623.6, 75.9, 939.2, 95.9], "size": 20.0}, {"role": "DECOR", "text": "PAP", "bbox": [214.1, 470.4, 263.2, 495.4], "size": 25.0}]$$),
    ('mama-whats-for-lunch', 12, $$$$, $$[]$$),
    ('mama-whats-for-lunch', 13, $$$$, $$[]$$),
    ('matthew-is-up', 0, $$The sun is up. Matthew is up.$$, $$[{"role": "BODY", "text": "The sun is up. Matthew is up.", "bbox": [732.0, 160.3, 968.8, 239.5], "size": 36.0}]$$),
    ('matthew-is-up', 1, $$Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.$$, $$[{"role": "BODY", "text": "Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.", "bbox": [687.2, 64.7, 1013.6, 187.1], "size": 36.0}]$$),
    ('matthew-is-up', 2, $$Matthew is hungry. Matthew pours the milk on his cereal. Matthew eats. Matthew eats it all up. Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.$$, $$[{"role": "BODY", "text": "Matthew is hungry. Matthew pours the milk on his cereal. Matthew eats. Matthew eats it all up.", "bbox": [56.7, 64.7, 498.2, 273.4], "size": 36.0}, {"role": "BODY", "text": "Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.", "bbox": [56.7, 323.9, 383.1, 446.2], "size": 36.0}]$$),
    ('matthew-is-up', 3, $$Matthew needs to poo. He sits on the loo and wipes his own bottom. Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.$$, $$[{"role": "BODY", "text": "Matthew needs to poo.", "bbox": [56.7, 109.7, 435.8, 145.7], "size": 36.0}, {"role": "BODY", "text": "He sits on the loo and wipes his own bottom.", "bbox": [56.7, 196.1, 423.5, 275.2], "size": 36.0}, {"role": "BODY", "text": "Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.", "bbox": [56.7, 325.6, 383.1, 448.1], "size": 36.0}]$$),
    ('matthew-is-up', 4, $$Matthew pulls off his pyjamas. He puts on his clothes. First he puts on his Spiderman underpants. Then he puts on his number 1 shirt. Then he puts on his pants.$$, $$[{"role": "BODY", "text": "Matthew pulls off his pyjamas. He puts on his clothes.", "bbox": [56.7, 92.3, 426.7, 214.7], "size": 36.0}, {"role": "BODY", "text": "First he puts on his Spiderman underpants. Then he puts on his number 1 shirt. Then he puts on his pants.", "bbox": [56.7, 265.1, 490.4, 473.9], "size": 36.0}]$$),
    ('matthew-is-up', 5, $$Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.$$, $$[{"role": "BODY", "text": "Mommy is sleeping. Daddy is sleeping. Lizwi is sleeping.", "bbox": [687.2, 64.7, 1013.6, 187.1], "size": 36.0}]$$),
    ('matthew-is-up', 6, $$So Matthew jumps. Matthew jumps small jumps in his room.$$, $$[{"role": "BODY", "text": "So Matthew jumps.", "bbox": [126.6, 83.1, 440.3, 119.1], "size": 36.0}, {"role": "BODY", "text": "Matthew jumps small jumps in his room.", "bbox": [106.8, 169.5, 460.1, 248.7], "size": 36.0}]$$),
    ('matthew-is-up', 7, $$Mommy is still sleeping. Daddy is still sleeping. Lizwi is still sleeping.$$, $$[{"role": "BODY", "text": "Mommy is still sleeping. Daddy is still sleeping. Lizwi is still sleeping.", "bbox": [56.7, 207.5, 453.2, 329.9], "size": 36.0}]$$),
    ('matthew-is-up', 8, $$So Matthew jumps. Matthew jumps in the passage. Matthew jumps in the bathroom.$$, $$[{"role": "BODY", "text": "So Matthew jumps. Matthew jumps in the passage.", "bbox": [56.7, 76.0, 413.2, 198.4], "size": 36.0}, {"role": "BODY", "text": "Matthew jumps in the bathroom.", "bbox": [56.7, 246.1, 228.9, 411.7], "size": 36.0}]$$),
    ('matthew-is-up', 9, $$Mommy is still sleeping. Daddy is still sleeping. Lizwi is still sleeping.$$, $$[{"role": "BODY", "text": "Mommy is still sleeping. Daddy is still sleeping. Lizwi is still sleeping.", "bbox": [56.7, 92.3, 453.2, 214.7], "size": 36.0}]$$),
    ('matthew-is-up', 10, $$So Matthew jumps on them. Matthew jumps on Mommy, on Daddy, on Lizwi, on the big bed.$$, $$[{"role": "BODY", "text": "So Matthew jumps on them.", "bbox": [56.7, 109.7, 509.8, 145.7], "size": 36.0}, {"role": "BODY", "text": "Matthew jumps on Mommy, on Daddy, on Lizwi, on the big bed.", "bbox": [56.7, 196.1, 312.1, 404.9], "size": 36.0}]$$),
    ('matthew-is-up', 11, $$Lizwi wakes up. Lizwi jumps! Matthew and Lizwi jump on Mommy and Daddy! Mommy wakes up.$$, $$[{"role": "BODY", "text": "Lizwi wakes up. Lizwi jumps!", "bbox": [56.7, 64.7, 308.8, 143.8], "size": 36.0}, {"role": "BODY", "text": "Matthew and Lizwi jump on Mommy and Daddy!", "bbox": [56.7, 194.2, 458.2, 273.4], "size": 36.0}, {"role": "BODY", "text": "Mommy wakes up.", "bbox": [56.7, 323.9, 367.3, 359.9], "size": 36.0}]$$),
