    ('meerkat-magic', 0, $$Bonke and Peo live near a hill.$$, $$[{"role": "BODY", "text": "Bonke and Peo live near a hill.", "bbox": [637.0, 116.5, 849.4, 184.5], "size": 30.0}]$$),
    ('meerkat-magic', 1, $$They like to run, hide and climb.$$, $$[{"role": "BODY", "text": "They like to run, hide and climb.", "bbox": [69.0, 328.4, 292.9, 396.4], "size": 30.0}]$$),
    ('meerkat-magic', 2, $$Peo doesn’t like to climb too high.$$, $$[{"role": "BODY", "text": "Peo doesn’t like to climb too high.", "bbox": [162.1, 103.7, 404.8, 171.7], "size": 30.0}]$$),
    ('meerkat-magic', 3, $$Sometimes they are lucky enough to find berries.$$, $$[{"role": "BODY", "text": "Sometimes they are lucky enough to find berries.", "bbox": [199.3, 207.5, 398.8, 351.5], "size": 30.0}]$$),
    ('meerkat-magic', 4, $$‘Did that meerkat just wave at me?’ asks Peo. Bonke laughs. ‘That’s impossible!’ he says.$$, $$[{"role": "BODY", "text": "‘Did that meerkat just wave at me?’ asks Peo.", "bbox": [91.5, 63.3, 475.4, 131.3], "size": 30.0}, {"role": "BODY", "text": "Bonke laughs. ‘That’s impossible!’ he says.", "bbox": [658.6, 63.3, 1042.2, 131.3], "size": 30.0}]$$),
    ('meerkat-magic', 5, $$The scampers meerkat up, up, up…$$, $$[{"role": "BODY", "text": "The scampers meerkat up, up, up…", "bbox": [681.5, 192.1, 1070.6, 268.0], "size": 30.0}]$$),
    ('meerkat-magic', 6, $$‘Let’s go!’$$, $$[{"role": "SFX", "text": "‘Let’s go!’", "bbox": [851.2, 96.5, 1059.3, 144.4], "size": 48.0}]$$),
    ('meerkat-magic', 7, $$‘Bonke, I’m scared.’$$, $$[{"role": "BODY", "text": "‘Bonke, I’m scared.’", "bbox": [828.6, 419.0, 1081.5, 519.0], "size": 48.0}]$$),
    ('meerkat-magic', 8, $$‘It’s okay, I’m here.’$$, $$[{"role": "BODY", "text": "‘It’s okay, I’m here.’", "bbox": [863.6, 67.3, 1096.1, 167.3], "size": 48.0}]$$),
    ('meerkat-magic', 9, $$$$, $$[]$$),
