    ('mina-and-the-birthday-dress', 0, $$Tomorrow is Mina’s birthday. She is having a party in the garden.$$, $$[{"role": "BODY", "text": "Tomorrow is Mina’s birthday. She is having a party in the garden.", "bbox": [653.7, 427.3, 1059.8, 488.9], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 1, $$Mina is going to the shops with Mum to buy a birthday dress.$$, $$[{"role": "BODY", "text": "Mina is going to the shops with Mum to buy a birthday dress.", "bbox": [74.9, 98.4, 426.8, 160.0], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 2, $$“I want a blue dress,” Mina says. Mum finds a lovely blue dress.$$, $$[{"role": "BODY", "text": "“I want a blue dress,” Mina says. Mum finds a lovely blue dress.", "bbox": [670.8, 256.5, 1030.0, 318.1], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 3, $$Mina shakes her head. “I don’t want a blue dress.”$$, $$[{"role": "BODY", "text": "Mina shakes her head. “I don’t want a blue dress.”", "bbox": [702.3, 255.8, 996.6, 317.4], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 4, $$“I want a pink dress,” Mina says. Mum shows her a beautiful pink dress.$$, $$[{"role": "BODY", "text": "“I want a pink dress,” Mina says. Mum shows her a beautiful pink dress.", "bbox": [635.8, 417.3, 1070.7, 478.9], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 5, $$Mina folds her arms. “I don’t want a pink dress.”$$, $$[{"role": "BODY", "text": "Mina folds her arms. “I don’t want a pink dress.”", "bbox": [703.9, 256.5, 997.8, 318.1], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 6, $$“I want a green dress,” Mina says. Mum holds out a pretty green dress.$$, $$[{"role": "BODY", "text": "“I want a green dress,” Mina says. Mum holds out a pretty green dress.", "bbox": [78.2, 389.0, 488.8, 450.6], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 7, $$Mina frowns. “I don’t want a green dress.”$$, $$[{"role": "BODY", "text": "Mina frowns. “I don’t want a green dress.”", "bbox": [695.6, 256.5, 1006.1, 318.1], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 8, $$Mum says, “You don’t want a blue dress, you don’t want a pink dress and you don’t want a green dress.”$$, $$[{"role": "BODY", "text": "Mum says, “You don’t want a blue dress, you don’t want a pink dress and you don’t want a green dress.”", "bbox": [90.2, 239.7, 477.7, 334.9], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 9, $$“What about this dress?”$$, $$[{"role": "BODY", "text": "“What about this dress?”", "bbox": [712.2, 273.3, 989.5, 301.3], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 10, $$Mina says, “Yes! I love yellow. I want the yellow dress.”$$, $$[{"role": "BODY", "text": "Mina says, “Yes! I love yellow. I want the yellow dress.”", "bbox": [151.5, 239.7, 416.4, 334.9], "size": 28.0}]$$),
    ('mina-and-the-birthday-dress', 11, $$$$, $$[]$$),
    ('mina-and-the-birthday-dress', 12, $$$$, $$[]$$),
    ('mina-and-the-birthday-dress', 13, $$$$, $$[]$$),
    ('miss-tiny-chef', 0, $$Kasini is eight years old. She loves to cook. She reads a cook book on the school bus every morning and before bedtime.$$, $$[{"role": "BODY", "text": "Kasini is eight years old. She loves to cook. She reads a cook book on the school bus every morning and before bedtime.", "bbox": [679.6, 224.1, 1021.2, 295.1], "size": 19.0}]$$),
    ('miss-tiny-chef', 1, $$Nobody knows her secret, that she sleeps with a wooden mingling stick every night. When she sleeps, she dreams that she is smiling, wearing a chef’s hat and holding her mingling stick high up in the air.$$, $$[{"role": "BODY", "text": "Nobody knows her secret, that she sleeps with a wooden mingling stick every night. When she sleeps, she dreams that she is smiling, wearing a chef’s hat and holding her mingling stick high up in the air.", "bbox": [703.7, 165.9, 977.0, 314.9], "size": 19.0}]$$),
    ('miss-tiny-chef', 2, $$Kasini loves to sing as she cooks. She sings to the carrots and dances with the flour.$$, $$[{"role": "BODY", "text": "Kasini loves to sing as she cooks. She sings to the carrots and dances with the flour.", "bbox": [715.4, 231.2, 974.5, 302.2], "size": 19.0}]$$),
    ('miss-tiny-chef', 3, $$She slices the cucumber and places two on top of her eyes. She BANGS the saucepans loudly as she jumps up and down.$$, $$[{"role": "BODY", "text": "She slices the cucumber and places two on top of her eyes. She BANGS the saucepans loudly as she jumps up and down.", "bbox": [687.4, 241.0, 1013.4, 312.0], "size": 19.0}]$$),
    ('miss-tiny-chef', 4, $$“GET BACK TO WORK.” the stick scolds. “Cooking is not work, it’s fun,” Kasini laughs. The stick tells her if the soup needs more salt, if the chicken needs more heat and when the Ugali is ready to eat.$$, $$[{"role": "BODY", "text": "“GET BACK TO WORK.” the stick scolds.", "bbox": [690.6, 201.2, 996.7, 220.6], "size": 19.0}, {"role": "BODY", "text": "“Cooking is not work, it’s fun,” Kasini laughs.", "bbox": [679.7, 253.2, 1007.6, 272.6], "size": 19.0}, {"role": "BODY", "text": "The stick tells her if the soup needs more salt, if the chicken needs more heat and when the Ugali is ready to eat.", "bbox": [680.2, 305.2, 1007.1, 376.2], "size": 19.0}]$$),
    ('miss-tiny-chef', 5, $$Sometimes Kasini doesn’t listen to the stick. “I will use my palm to taste the soup,” she says.$$, $$[{"role": "BODY", "text": "Sometimes Kasini doesn’t listen to the stick. “I will use my palm to taste the soup,” she says.", "bbox": [686.7, 208.3, 1000.6, 279.3], "size": 19.0}]$$),
    ('miss-tiny-chef', 6, $$“I will use my mouth to taste the chicken,” she decides. The stick laughs for she is young and it is old. Older than the cutlery in the house, Older than Kasini’s older brother. So old it knows all the great recipes by heart.$$, $$[{"role": "BODY", "text": "“I will use my mouth to taste the chicken,” she decides. The stick laughs for she is young and it is old. Older than the cutlery in the house, Older than Kasini’s older brother. So old it knows all the great recipes by heart.", "bbox": [689.6, 199.6, 995.7, 348.2], "size": 19.0}]$$),
    ('miss-tiny-chef', 7, $$Kasini adds more salt, pepper and curry powder to the soup. This is wrong and she knows it but she is only being stubborn.$$, $$[{"role": "BODY", "text": "Kasini adds more salt, pepper and curry powder to the soup. This is wrong and she knows it but she is only being stubborn.", "bbox": [691.1, 208.3, 996.2, 279.3], "size": 19.0}]$$),
    ('miss-tiny-chef', 8, $$The stick doesn’t like being disrespected, it changes colour from brown to red to show Kasini that it is angry.$$, $$[{"role": "BODY", "text": "The stick doesn’t like being disrespected, it changes colour from brown to red to show Kasini that it is angry.", "bbox": [700.4, 247.9, 993.3, 318.9], "size": 19.0}]$$),
    ('miss-tiny-chef', 9, $$“The soup will BURN without the mingling stick!” moans Kasini.$$, $$[{"role": "BODY", "text": "“The soup will BURN without the mingling stick!” moans Kasini.", "bbox": [724.1, 208.7, 976.6, 253.7], "size": 19.0}]$$),
    ('miss-tiny-chef', 10, $$She sings for the stick, but there is no change. “I am sorry,” she says. The stick turns back to brown just in time and Kasini hugs it in joy.$$, $$[{"role": "BODY", "text": "She sings for the stick, but there is no change.", "bbox": [757.4, 204.7, 924.3, 249.7], "size": 19.0}, {"role": "BODY", "text": "“I am sorry,” she says. The stick turns back to brown just in time and Kasini hugs it in joy.", "bbox": [705.7, 282.6, 976.0, 353.6], "size": 19.0}]$$),
    ('miss-tiny-chef', 11, $$“Now I can serve mummy the food I made,” Kasini says excitedly. “The food we made,” she giggles, as she tucks the stick away.$$, $$[{"role": "BODY", "text": "“Now I can serve mummy the food I made,” Kasini says excitedly. “The food we made,” she giggles, as she tucks the stick away.", "bbox": [709.4, 235.8, 972.3, 332.4], "size": 19.0}]$$),
    ('miss-tiny-chef', 12, $$$$, $$[]$$),
    ('miss-tiny-chef', 13, $$$$, $$[]$$),
    ('moms-hands', 0, $$Mom holds me close. Her hands move. I smile.$$, $$[{"role": "BODY", "text": "Mom holds me close. Her hands move.", "bbox": [165.8, 244.9, 401.1, 297.7], "size": 24.0}, {"role": "BODY", "text": "I smile.", "bbox": [245.5, 331.3, 321.4, 355.3], "size": 24.0}]$$),
    ('moms-hands', 1, $$“Good morning,” Mom signs. Her hands dance in the air. I wave back.$$, $$[{"role": "BODY", "text": "“Good morning,” Mom signs.", "bbox": [670.3, 92.3, 856.1, 145.1], "size": 24.0}, {"role": "BODY", "text": "Her hands dance in the air.", "bbox": [636.3, 250.6, 828.4, 303.4], "size": 24.0}, {"role": "BODY", "text": "I wave back.", "bbox": [662.9, 365.8, 801.8, 389.8], "size": 24.0}]$$),
    ('moms-hands', 2, $$Mom shows me “love”. She points to her heart. Then to me.$$, $$[{"role": "BODY", "text": "Mom shows me “love”.", "bbox": [724.4, 350.5, 976.4, 374.5], "size": 24.0}, {"role": "BODY", "text": "She points to her heart. Then to me.", "bbox": [719.1, 408.1, 981.7, 460.9], "size": 24.0}]$$),
    ('moms-hands', 3, $$At breakfast, we sign “eat”. I tap my mouth with my hand. Mom claps, “Yes!”$$, $$[{"role": "BODY", "text": "At breakfast, we sign “eat”.", "bbox": [93.1, 228.6, 397.3, 252.6], "size": 24.0}, {"role": "BODY", "text": "I tap my mouth with my hand. Mom claps, “Yes!”", "bbox": [76.9, 286.2, 413.5, 339.0], "size": 24.0}]$$),
    ('moms-hands', 4, $$When we play, Mom signs “ball”. I roll it to her. She laughs.$$, $$[{"role": "BODY", "text": "When we play, Mom signs “ball”.", "bbox": [306.2, 146.2, 497.5, 198.9], "size": 24.0}, {"role": "BODY", "text": "I roll it to her. She laughs.", "bbox": [658.0, 302.8, 806.0, 355.6], "size": 24.0}]$$),
    ('moms-hands', 5, $$Mom signs “bird”. We watch the birds fly. I flap my arms too.$$, $$[{"role": "BODY", "text": "Mom signs “bird”.", "bbox": [809.1, 233.5, 1003.7, 257.5], "size": 24.0}, {"role": "BODY", "text": "We watch the birds fly. I flap my arms too.", "bbox": [778.0, 291.1, 1034.8, 343.9], "size": 24.0}]$$),
    ('moms-hands', 6, $$At story time, Mom signs each word. Her hands paint pictures in the air. I listen with my eyes.$$, $$[{"role": "BODY", "text": "At story time, Mom signs each word. Her hands paint pictures in the air.", "bbox": [79.8, 291.0, 487.2, 343.8], "size": 24.0}, {"role": "BODY", "text": "I listen with my eyes.", "bbox": [168.0, 377.4, 398.9, 401.4], "size": 24.0}]$$),
    ('moms-hands', 7, $$When I feel sad. Mom signs “hug”. She wraps me in her arms.$$, $$[{"role": "BODY", "text": "When I feel sad. Mom signs “hug”.", "bbox": [204.1, 357.1, 396.9, 409.9], "size": 24.0}, {"role": "BODY", "text": "She wraps me in her arms.", "bbox": [151.6, 443.5, 449.4, 467.5], "size": 24.0}]$$),
    ('moms-hands', 8, $$Mom meets her Deaf friends. I watch their moving hands.$$, $$[{"role": "BODY", "text": "Mom meets her Deaf friends.", "bbox": [343.4, 290.7, 519.8, 343.5], "size": 24.0}, {"role": "BODY", "text": "I watch their moving hands.", "bbox": [620.2, 290.7, 784.4, 343.5], "size": 24.0}]$$),
    ('moms-hands', 9, $$I learn to sign “friend”. I hold my hands together. Mom smiles proudly.$$, $$[{"role": "BODY", "text": "I learn to sign “friend”. I hold my hands together.", "bbox": [138.9, 462.2, 428.0, 515.0], "size": 24.0}, {"role": "BODY", "text": "Mom smiles proudly.", "bbox": [937.9, 378.6, 1070.5, 431.4], "size": 24.0}]$$),
    ('moms-hands', 10, $$Before bed, Mom signs “I love you”. Her hands make a special shape. I copy her.$$, $$[{"role": "BODY", "text": "Before bed, Mom signs “I love you”.", "bbox": [84.7, 268.6, 482.2, 292.6], "size": 24.0}, {"role": "BODY", "text": "Her hands make a special shape. I copy her.", "bbox": [97.4, 326.2, 469.5, 379.1], "size": 24.0}]$$),
    ('moms-hands', 11, $$Mom talks with her hands. I love Mom’s hands. Mom and me. Forever.$$, $$[{"role": "BODY", "text": "Mom talks with her hands. I love Mom’s hands.", "bbox": [703.8, 303.4, 997.0, 356.2], "size": 24.0}, {"role": "BODY", "text": "Mom and me. Forever.", "bbox": [723.8, 389.8, 977.0, 413.8], "size": 24.0}]$$),
    ('moms-hands', 12, $$$$, $$[]$$),
    ('moms-hands', 13, $$$$, $$[]$$),
    ('moms-red-coat', 0, $$I love Mom’s coat! It’s red and long and warm. And it smells like Mom!$$, $$[{"role": "BODY", "text": "I love Mom’s coat! It’s red and long and warm. And it smells like Mom!", "bbox": [151.2, 239.8, 415.7, 326.5], "size": 23.2}]$$),
    ('moms-red-coat', 1, $$I love doing things with Mom! We picnic outside. She hugs me when I come home from school. We work in the garden. At night, she holds me tight until I fall asleep.$$, $$[{"role": "SFX", "text": "I love doing things with Mom!", "bbox": [56.7, 66.9, 476.4, 96.9], "size": 30.0}, {"role": "BODY", "text": "We picnic outside.", "bbox": [297.6, 176.6, 471.4, 197.6], "size": 21.0}, {"role": "BODY", "text": "She hugs me when I come home from school.", "bbox": [837.6, 137.5, 1019.6, 208.9], "size": 21.0}, {"role": "BODY", "text": "We work in the garden.", "bbox": [56.7, 404.6, 280.7, 425.6], "size": 21.0}, {"role": "BODY", "text": "At night, she holds me tight until I fall asleep.", "bbox": [623.6, 384.4, 836.5, 430.6], "size": 21.0}]$$),
    ('moms-red-coat', 2, $$‘Good news!’ says Mom. ‘I found a job! I will be away all week, but I’ll come home on weekends!’$$, $$[{"role": "BODY", "text": "‘Good news!’ says Mom. ‘I found a job! I will be away all week, but I’ll come home on weekends!’", "bbox": [232.2, 222.2, 499.1, 369.6], "size": 21.7}]$$),
    ('moms-red-coat', 3, $$‘Who will hold me at night, Mom?’ ‘Who will hug me, picnic with me, garden with me?’$$, $$[{"role": "BODY", "text": "‘Who will hold me at night, Mom?’ ‘Who will hug me, picnic with me, garden with me?’", "bbox": [124.9, 214.4, 447.8, 353.9], "size": 28.9}]$$),
    ('moms-red-coat', 4, $$‘I can see that you are sad. I will leave my red coat here with you.’ ‘When you see it, remember that I love you and I’m coming back.’$$, $$[{"role": "BODY", "text": "‘I can see that you are sad. I will leave my red coat here with you.’", "bbox": [646.3, 161.9, 1054.5, 263.9], "size": 30.0}, {"role": "BODY", "text": "‘When you see it, remember that I love you and I’m coming back.’", "bbox": [692.2, 297.3, 1008.6, 383.5], "size": 23.5}]$$),
    ('moms-red-coat', 5, $$I drag the red coat outside – it’s my picnic blanket! It feels like Mom is with me. Oops! Juice spill!$$, $$[{"role": "BODY", "text": "I drag the red coat outside – it’s my picnic blanket! It feels like Mom is with me.", "bbox": [85.6, 221.5, 481.3, 316.2], "size": 25.5}, {"role": "BODY", "text": "Oops! Juice spill!", "bbox": [997.9, 98.2, 1101.2, 144.4], "size": 21.0}]$$),
    ('moms-red-coat', 6, $$I am sad that Mom’s not waiting at the door when I come home. I put on her coat. It’s warm and it smells like her. It feels like a hug! Oops! Paint!$$, $$[{"role": "BODY", "text": "I am sad that Mom’s not waiting at the door when I come home.", "bbox": [71.0, 181.7, 496.0, 227.9], "size": 21.0}, {"role": "BODY", "text": "I put on her coat.", "bbox": [201.5, 257.3, 365.4, 278.3], "size": 21.0}, {"role": "SFX", "text": "It’s warm and it smells like her. It feels like a hug!", "bbox": [61.9, 309.2, 505.1, 375.2], "size": 30.0}, {"role": "BODY", "text": "Oops! Paint!", "bbox": [1007.0, 145.0, 1065.1, 191.2], "size": 21.0}]$$),
    ('moms-red-coat', 7, $$I help Gogo in the garden. The long coat on the branch scares away the chickens! It feels like Mom is gardening with us. Oops! Mud!$$, $$[{"role": "BODY", "text": "I help Gogo in the garden.", "bbox": [158.8, 62.8, 408.1, 83.8], "size": 21.0}, {"role": "BODY", "text": "The long coat on the branch scares away the chickens!", "bbox": [623.6, 61.3, 967.2, 107.5], "size": 21.0}, {"role": "BODY", "text": "It feels like Mom is gardening with us.", "bbox": [623.6, 153.7, 859.8, 255.7], "size": 30.0}, {"role": "BODY", "text": "Oops! Mud!", "bbox": [783.8, 331.7, 841.9, 377.9], "size": 21.0}]$$),
    ('moms-red-coat', 8, $$When it’s dark, I miss Mom most. Gogo covers me with her warm coat. It feels like Mom is holding me as I fall asleep. Oops! Cookie crumbs!$$, $$[{"role": "BODY", "text": "When it’s dark, I miss Mom most.", "bbox": [110.8, 125.4, 456.2, 148.4], "size": 23.0}, {"role": "BODY", "text": "Gogo covers me with her warm coat.", "bbox": [88.2, 180.6, 478.7, 203.6], "size": 23.0}, {"role": "BODY", "text": "It feels like Mom is holding me as I fall asleep.", "bbox": [58.6, 239.1, 508.4, 307.3], "size": 31.0}, {"role": "BODY", "text": "Oops! Cookie crumbs!", "bbox": [665.9, 332.1, 746.5, 403.5], "size": 21.0}]$$),
    ('moms-red-coat', 9, $$Mom’s red coat is warm and smells like… paint, juice, mud and cookie crumbs! Oops! We need to wash it!$$, $$[{"role": "BODY", "text": "Mom’s red coat is warm and smells like…", "bbox": [56.7, 160.4, 287.6, 262.4], "size": 30.0}, {"role": "BODY", "text": "paint, juice,", "bbox": [129.3, 305.7, 219.0, 351.6], "size": 21.0}, {"role": "BODY", "text": "mud", "bbox": [213.8, 356.4, 257.6, 377.4], "size": 21.0}, {"role": "BODY", "text": "and cookie crumbs!", "bbox": [266.5, 377.4, 455.9, 398.4], "size": 21.0}, {"role": "BODY", "text": "Oops! We need to wash it!", "bbox": [905.6, 71.3, 1021.3, 142.7], "size": 21.0}]$$),
    ('moms-red-coat', 10, $$The wind blows the red coat off the washing line... up in t o the air! It flies overthefence! It flies overthetaxi! Oops! Who did the coat fall on?$$, $$[{"role": "BODY", "text": "The wind blows the red coat off the washing line...", "bbox": [72.9, 63.6, 494.0, 131.8], "size": 31.0}, {"role": "BODY", "text": "up in t o the air!", "bbox": [171.1, 164.2, 390.8, 213.9], "size": 29.6}, {"role": "SFX", "text": "It flies overthefence! It flies overthetaxi!", "bbox": [208.3, 268.3, 520.9, 500.3], "size": 30.6}, {"role": "BODY", "text": "Oops! Who did the coat fall on?", "bbox": [945.0, 181.8, 1030.0, 278.4], "size": 21.0}]$$),
    ('moms-red-coat', 11, $$I run and grab it! ‘Found you, coat!’ The red coat smells like Mom again. ‘Oh!’ ‘Found you, Mom! You’re back!’$$, $$[{"role": "BODY", "text": "I run and grab it!", "bbox": [56.7, 181.8, 216.5, 202.8], "size": 21.0}, {"role": "BODY", "text": "‘Found you, coat!’ The red coat smells like Mom again.", "bbox": [110.0, 263.7, 456.9, 332.0], "size": 26.0}, {"role": "SFX", "text": "‘Oh!’ ‘Found you, Mom! You’re back!’", "bbox": [709.0, 71.5, 991.8, 139.7], "size": 31.0}]$$),
    ('moms-red-coat', 12, $$$$, $$[]$$),
    ('moms-red-coat', 13, $$$$, $$[]$$),
    ('monkey-business', 0, $$In the wild, there are many different animals: big and small, fast and s l o w. But every animal has a part to play.$$, $$[{"role": "BODY", "text": "In the wild, there are many different animals:", "bbox": [159.8, 119.8, 388.4, 163.8], "size": 20.0}, {"role": "BODY", "text": "big and small, fast and s l o w.", "bbox": [679.5, 64.3, 1019.8, 166.5], "size": 36.0}, {"role": "BODY", "text": "But every animal has a part to play.", "bbox": [763.1, 318.3, 938.3, 362.3], "size": 20.0}]$$),
    ('monkey-business', 1, $$Elephants have long noses called trunks that sniff out water. They can find a drink even when it’s hard to see. And when they do, they trumpet to their friends: toot-toot!$$, $$[{"role": "BODY", "text": "Elephants have long noses called trunks that sniff out water. They can find a drink even when it’s hard to see.", "bbox": [85.0, 273.4, 349.9, 365.4], "size": 20.0}, {"role": "SFX", "text": "And when they do, they trumpet to their friends: toot-toot!", "bbox": [666.1, 83.8, 872.7, 273.7], "size": 36.3}]$$),
    ('monkey-business', 2, $$Rhinos like routine. They follow the same paths again and again, and make wide trails as they crash through the bush.$$, $$[{"role": "BODY", "text": "Rhinos like routine. They follow the same paths again and again,", "bbox": [85.0, 81.4, 413.2, 285.1], "size": 35.0}, {"role": "BODY", "text": "and make wide trails as they crash through the bush.", "bbox": [85.0, 428.7, 463.6, 485.1], "size": 20.0}]$$),
    ('monkey-business', 3, $$Hippos love to eat sweet, green grass, and lots of it. Munch-munch- munch. They short keep so the the water grass is next easier to to the reach. river$$, $$[{"role": "BODY", "text": "Hippos love to eat sweet, green grass, and lots of it. Munch-munch- munch.", "bbox": [77.7, 359.7, 479.0, 527.0], "size": 35.0}, {"role": "BODY", "text": "They short keep so the the water grass is next easier to to the reach. river", "bbox": [678.2, 454.3, 1030.6, 498.3], "size": 20.0}]$$),
    ('monkey-business', 4, $$But what about monkeys? Oh, monkeys have an especially important job.$$, $$[{"role": "SFX", "text": "But what about monkeys?", "bbox": [706.1, 120.4, 994.7, 199.6], "size": 36.0}, {"role": "BODY", "text": "Oh, monkeys have an especially important job.", "bbox": [693.5, 431.0, 1007.3, 497.7], "size": 20.0}]$$),
    ('monkey-business', 5, $$From sunrise to sunset, they’re on the go – climbing , tumbling and searching for food.$$, $$[{"role": "BODY", "text": "From sunrise to sunset, they’re on the go – climbing , tumbling and searching for food.", "bbox": [711.1, 239.7, 1071.7, 514.0], "size": 22.5}]$$),
    ('monkey-business', 6, $$Monkeys dangle by their feet from trees, looking at the world .nwod- edispu$$, $$[{"role": "BODY", "text": "Monkeys dangle by their feet from trees, looking at the world", "bbox": [742.0, 155.9, 941.4, 223.9], "size": 20.0}, {"role": "BODY", "text": ".nwod- edispu", "bbox": [742.0, 288.4, 937.6, 406.4], "size": 60.0}]$$),
    ('monkey-business', 7, $$They swing from branch to branch in groups of two, three and four at a time. What fun!$$, $$[{"role": "SFX", "text": "They swing from branch to branch in groups of two, three and four at a time. What fun!", "bbox": [90.5, 101.4, 357.0, 406.8], "size": 28.6}]$$),
    ('monkey-business', 8, $$Mama monkeys can do it all with a baby clinging to their belly. What do the little ones see from ?ereht nwod$$, $$[{"role": "BODY", "text": "Mama monkeys can do it all with a baby clinging to their belly. What do the little ones see from", "bbox": [85.0, 209.5, 396.9, 277.5], "size": 20.0}, {"role": "BODY", "text": "?ereht nwod", "bbox": [85.0, 340.6, 301.4, 376.6], "size": 36.0}]$$),
    ('monkey-business', 9, $$When they want a snack, monkeys pick a flea straight from a chommie’s back.$$, $$[{"role": "BODY", "text": "When they want a snack, monkeys pick a flea straight from a chommie’s back.", "bbox": [753.0, 80.1, 931.0, 229.3], "size": 22.0}]$$),
    ('monkey-business', 10, $$And when they’re hot and tired, they cannonba ll into the water.$$, $$[{"role": "BODY", "text": "And when they’re hot and tired, they cannonba ll", "bbox": [85.0, 84.4, 432.8, 292.9], "size": 42.8}, {"role": "BODY", "text": "into the water.", "bbox": [346.4, 436.5, 482.4, 456.5], "size": 20.0}]$$),
    ('monkey-business', 11, $$What’s the important job that monkeys have? They play all day. And that’s hard work!$$, $$[{"role": "BODY", "text": "What’s the important job that monkeys have? They play all day.", "bbox": [739.1, 126.3, 978.0, 194.3], "size": 20.0}, {"role": "SFX", "text": "And that’s hard work!", "bbox": [732.8, 425.2, 919.8, 496.4], "size": 36.0}]$$),
    ('monkey-business', 12, $$$$, $$[]$$),
    ('monkey-business', 13, $$$$, $$[]$$),
    ('mud', 0, $$Zama has spent all morning in a mucky puddle, making a new friend.$$, $$[{"role": "BODY", "text": "Zama has spent all morning in a mucky puddle, making a new friend.", "bbox": [154.5, 225.2, 412.5, 354.1], "size": 28.0}]$$),
    ('mud', 1, $$“Let’s have some fun, Mud. What do you want to do?” “Something naughty,” grins Mud.$$, $$[{"role": "BODY", "text": "“Let’s have some fun, Mud. What do you want to do?”", "bbox": [58.9, 243.9, 254.3, 372.7], "size": 28.0}, {"role": "BODY", "text": "“Something naughty,” grins Mud.", "bbox": [906.4, 256.2, 1055.2, 351.4], "size": 28.0}]$$),
    ('mud', 2, $$SQUELCH! WHEEEE!$$, $$[{"role": "SFX", "text": "SQUELCH!", "bbox": [168.4, 73.1, 398.5, 121.1], "size": 48.0}, {"role": "SFX", "text": "WHEEEE!", "bbox": [749.2, 73.1, 951.6, 121.1], "size": 48.0}]$$),
    ('mud', 3, $$“Oh no, Mud! You made Mama’s clean sheets dirty!”$$, $$[{"role": "BODY", "text": "“Oh no, Mud! You made Mama’s clean sheets dirty!”", "bbox": [62.4, 225.2, 240.9, 354.1], "size": 28.0}]$$),
    ('mud', 4, $$“Zama! What have you done to my washing?” “It’s not me, Mama. It’s Mud!” cries Zama.$$, $$[{"role": "BODY", "text": "“Zama! What have you done to my washing?”", "bbox": [63.2, 131.9, 203.3, 294.3], "size": 28.0}, {"role": "BODY", "text": "“It’s not me, Mama. It’s Mud!” cries Zama.", "bbox": [825.6, 158.8, 1034.6, 254.0], "size": 28.0}]$$),
    ('mud', 5, $$“Mud! What did you do to Mama’s clean floor?” But Mud ignores Zama and scampers into the kitchen.$$, $$[{"role": "BODY", "text": "“Mud! What did you do to Mama’s clean floor?”", "bbox": [119.8, 63.3, 447.1, 124.9], "size": 28.0}, {"role": "BODY", "text": "But Mud ignores Zama and scampers into the kitchen.", "bbox": [673.6, 60.4, 1027.2, 122.0], "size": 28.0}]$$),
    ('mud', 6, $$“Zama! What is this mess?” “It’s not me, Mama. It’s Mud!”$$, $$[{"role": "BODY", "text": "“Zama! What is this mess?”", "bbox": [59.1, 138.6, 207.4, 233.8], "size": 28.0}, {"role": "BODY", "text": "“It’s not me, Mama. It’s Mud!”", "bbox": [825.6, 140.5, 1034.6, 202.1], "size": 28.0}]$$),
    ('mud', 7, $$Oh dear! Is there anything Mud didn’t touch?$$, $$[{"role": "BODY", "text": "Oh dear! Is there anything Mud didn’t touch?", "bbox": [682.9, 62.5, 1017.9, 124.2], "size": 28.0}]$$),
    ('mud', 8, $$“It’s Mud, Mama!” pleads Zama. “I don’t know how to stop it!” “Enough nonsense, Zama! Get in the bath. Right now!”$$, $$[{"role": "BODY", "text": "“It’s Mud, Mama!” pleads Zama. “I don’t know how to stop it!”", "bbox": [81.9, 68.9, 485.0, 130.5], "size": 28.0}, {"role": "BODY", "text": "“Enough nonsense, Zama! Get in the bath. Right now!”", "bbox": [941.2, 84.4, 1085.6, 246.8], "size": 28.0}]$$),
    ('mud', 9, $$Zama sinks into the bubbles. It feels so good to be clean again! But where is Mud?$$, $$[{"role": "BODY", "text": "Zama sinks into the bubbles. It feels so good to be clean again!", "bbox": [168.5, 166.4, 480.6, 261.6], "size": 28.0}, {"role": "BODY", "text": "But where is Mud?", "bbox": [795.7, 114.8, 1029.8, 142.8], "size": 28.0}]$$),
    ('mud', 10, $$Suddenly... KER- SPLASH!$$, $$[{"role": "BODY", "text": "Suddenly...", "bbox": [96.0, 114.8, 230.7, 142.8], "size": 28.0}, {"role": "SFX", "text": "KER- SPLASH!", "bbox": [768.9, 217.3, 968.1, 312.3], "size": 50.0}]$$),
    ('mud', 11, $$“Zama! The bath is full of mud!” “I know, Mama,” says Zama crossly. “And it can stay there!”$$, $$[{"role": "BODY", "text": "“Zama! The bath is full of mud!”", "bbox": [318.9, 81.2, 473.4, 176.4], "size": 28.0}, {"role": "BODY", "text": "“I know, Mama,” says Zama crossly. “And it can stay there!”", "bbox": [704.2, 81.2, 996.6, 176.4], "size": 28.0}]$$),
    ('mud', 12, $$$$, $$[]$$),
    ('mud', 13, $$$$, $$[]$$),
    ('my-dream-in-the-drawer', 0, $$I kept it hidden, safe and sound, In my drawer of socks. I once had a dream, so small and light, I kept it in a box.$$, $$[{"role": "BODY", "text": "I kept it hidden, safe and sound, In my drawer of socks.", "bbox": [615.1, 118.3, 875.4, 164.3], "size": 20.0}, {"role": "BODY", "text": "I once had a dream, so small and light, I kept it in a box.", "bbox": [104.9, 484.9, 421.1, 530.9], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 1, $$This tiny dream, I had, you see, Was mostly about me …$$, $$[{"role": "BODY", "text": "This tiny dream, I had, you see, Was mostly about me …", "bbox": [66.8, 96.6, 320.1, 142.6], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 2, $$SpaceSelfie! … who I’d be, and where I’d go, And what I’d one day see.$$, $$[{"role": "BODY", "text": "SpaceSelfie!", "bbox": [92.9, 184.5, 185.5, 222.3], "size": 18.9}, {"role": "BODY", "text": "… who I’d be, and where I’d go, And what I’d one day see.", "bbox": [689.4, 496.3, 948.0, 542.3], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 3, $$At first, it was a little dream, Until one day it grew, And so I took it out for air, To show my dream to you.$$, $$[{"role": "BODY", "text": "At first, it was a little dream, Until one day it grew,", "bbox": [170.1, 490.4, 397.7, 536.4], "size": 20.0}, {"role": "BODY", "text": "And so I took it out for air, To show my dream to you.", "bbox": [731.3, 490.4, 944.2, 536.4], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 4, $$And then my dream, it got so big, I had to let it out ...$$, $$[{"role": "BODY", "text": "And then my dream, it got so big, I had to let it out ...", "bbox": [723.8, 236.9, 997.1, 282.9], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 5, $$I took it to the playground, And watched it bounce about.$$, $$[{"role": "BODY", "text": "I took it to the playground, And watched it bounce about.", "bbox": [642.8, 61.6, 887.5, 107.6], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 6, $$Then all the kids, they saw my dream, And said, “We want one too!” I said to them, “Ok, no probs.” And told them what to do. Wow!!! Awesome! What??$$, $$[{"role": "BODY", "text": "Then all the kids, they saw my dream, And said, “We want one too!” I said to them, “Ok, no probs.” And told them what to do.", "bbox": [152.8, 55.3, 459.1, 153.3], "size": 20.0}, {"role": "SFX", "text": "Wow!!!", "bbox": [479.8, 139.8, 522.5, 154.8], "size": 15.0}, {"role": "BODY", "text": "Awesome!", "bbox": [109.6, 380.0, 176.6, 396.0], "size": 16.0}, {"role": "SFX", "text": "What??", "bbox": [463.7, 476.4, 513.0, 491.4], "size": 15.0}]$$),
    ('my-dream-in-the-drawer', 7, $$“Well, first you think of what you want. Believe it with your heart.$$, $$[{"role": "BODY", "text": "“Well, first you think of what you want. Believe it with your heart.", "bbox": [679.6, 256.3, 989.8, 302.3], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 8, $$To get a dream as big as mine, This is the place to start.”$$, $$[{"role": "BODY", "text": "To get a dream as big as mine, This is the place to start.”", "bbox": [722.8, 433.0, 973.1, 479.0], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 9, $$“And once it’s big enough,” I said. “You’ve got to let it free To fly up high across the world, For all the world to see.”$$, $$[{"role": "BODY", "text": "“And once it’s big enough,” I said. “You’ve got to let it free To fly up high across the world, For all the world to see.”", "bbox": [149.1, 220.2, 414.0, 318.2], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 10, $$And at that point, my big old dream, Which once was in a drawer … Shook and climbed, Took to the sky …$$, $$[{"role": "BODY", "text": "And at that point, my big old dream, Which once was in a drawer … Shook and climbed, Took to the sky …", "bbox": [708.0, 451.4, 1008.0, 549.4], "size": 20.0}]$$),
    ('my-dream-in-the-drawer', 11, $$And soared ... and soared … ... and soared.$$, $$[{"role": "BODY", "text": "And soared ...", "bbox": [737.2, 345.3, 849.3, 365.3], "size": 20.0}, {"role": "BODY", "text": "and soared … ... and soared.", "bbox": [798.8, 391.4, 1087.3, 469.5], "size": 32.0}]$$),
    ('my-dream-in-the-drawer', 12, $$gluehere gluehere gluehere Don’t cut it out! Trace it, colour it, and make it your own! glue here gluehere gluehere gluehere glue here gluehere gluehere$$, $$[{"role": "BODY", "text": "gluehere", "bbox": [358.5, 267.4, 402.1, 303.6], "size": 13.6}, {"role": "BODY", "text": "gluehere", "bbox": [298.6, 333.9, 322.1, 372.6], "size": 8.8}, {"role": "BODY", "text": "gluehere", "bbox": [454.5, 190.7, 496.8, 228.9], "size": 13.4}, {"role": "SFX", "text": "Don’t cut it out! Trace it, colour it, and make it your own!", "bbox": [176.5, 429.8, 421.3, 510.8], "size": 27.0}, {"role": "BODY", "text": "glue here", "bbox": [621.9, 33.0, 668.5, 53.0], "size": 13.0}, {"role": "BODY", "text": "gluehere", "bbox": [734.5, 66.2, 778.9, 101.1], "size": 13.6}, {"role": "BODY", "text": "gluehere", "bbox": [654.6, 191.9, 696.1, 231.4], "size": 13.3}, {"role": "BODY", "text": "gluehere", "bbox": [840.7, 139.0, 884.2, 175.6], "size": 13.6}, {"role": "BODY", "text": "glue here", "bbox": [932.0, 200.6, 970.6, 214.5], "size": 10.5}, {"role": "BODY", "text": "gluehere", "bbox": [748.7, 267.5, 791.5, 305.1], "size": 13.5}, {"role": "BODY", "text": "gluehere", "bbox": [831.5, 334.2, 853.5, 373.1], "size": 8.5}]$$),
    ('my-dream-in-the-drawer', 13, $$$$, $$[]$$),
    ('my-inside-weather', 0, $$It’s easy to talk about the weather outside, even if it changes all the time.$$, $$[{"role": "BODY", "text": "It’s easy to talk about the weather outside, even if it changes all the time.", "bbox": [59.1, 233.0, 507.8, 339.0], "size": 30.0}]$$),
    ('my-inside-weather', 1, $$But it’s hard to talk about the weather inside me. Sometimes it feels like people don’t understand.$$, $$[{"role": "BODY", "text": "But it’s hard to talk about the weather inside me. Sometimes it feels like people don’t understand.", "bbox": [61.5, 233.0, 505.5, 339.0], "size": 30.0}]$$),
    ('my-inside-weather', 2, $$Do you feel like that too?$$, $$[{"role": "BODY", "text": "Do you feel like that too?", "bbox": [122.2, 271.0, 444.7, 301.0], "size": 30.0}]$$),
    ('my-inside-weather', 3, $$Some days my mind is full of sunshine and rainbows. I feel like I can do anything.$$, $$[{"role": "BODY", "text": "Some days my mind is full of sunshine and rainbows. I feel like I can do anything.", "bbox": [71.0, 233.0, 496.0, 339.0], "size": 30.0}]$$),
    ('my-inside-weather', 4, $$On other days my head is full of fog and clouds. It’s hard to listen to what people are saying or to remember things.$$, $$[{"role": "BODY", "text": "On other days my head is full of fog and clouds. It’s hard to listen to what people are saying or to remember things.", "bbox": [61.8, 214.0, 505.1, 358.0], "size": 30.0}]$$),
    ('my-inside-weather', 5, $$I sometimes wake up feeling like it’s windy and wild in my head. I feel tired and grumpy.$$, $$[{"role": "BODY", "text": "I sometimes wake up feeling like it’s windy and wild in my head. I feel tired and grumpy.", "bbox": [74.8, 233.0, 492.1, 339.0], "size": 30.0}]$$),
    ('my-inside-weather', 6, $$And sometimes it feels like it’s raining inside me. It can be a drizzle making me feel sad, or a storm making me feel angry.$$, $$[{"role": "BODY", "text": "And sometimes it feels like it’s raining inside me. It can be a drizzle making me feel sad, or a storm making me feel angry.", "bbox": [73.4, 214.0, 493.6, 358.0], "size": 30.0}]$$),
    ('my-inside-weather', 7, $$Sometimes the weather inside me doesn’t match the weather outside.$$, $$[{"role": "BODY", "text": "Sometimes the weather inside me doesn’t match the weather outside.", "bbox": [86.8, 233.0, 480.1, 339.0], "size": 30.0}]$$),
    ('my-inside-weather', 8, $$Sometimes my inside weather doesn’t match how I want to feel or how I think I should feel.$$, $$[{"role": "BODY", "text": "Sometimes my inside weather doesn’t match how I want to feel or how I think I should feel.", "bbox": [73.2, 233.0, 493.7, 339.0], "size": 30.0}]$$),
    ('my-inside-weather', 9, $$Is that okay? Yes, of course it is.$$, $$[{"role": "BODY", "text": "Is that okay?", "bbox": [202.2, 195.0, 364.7, 225.0], "size": 30.0}, {"role": "BODY", "text": "Yes, of course it is.", "bbox": [165.6, 347.0, 401.3, 377.0], "size": 30.0}]$$),
    ('my-inside-weather', 10, $$The best thing to do when we feel like our inside weather is strange is to tell someone we love, and talk about it.$$, $$[{"role": "BODY", "text": "The best thing to do when we feel like our inside weather is strange is to tell someone we love, and talk about it.", "bbox": [65.4, 214.0, 501.6, 358.0], "size": 30.0}]$$),
    ('my-inside-weather', 11, $$They’ve got inside weather too, and they’ll understand.$$, $$[{"role": "BODY", "text": "They’ve got inside weather too, and they’ll understand.", "bbox": [80.2, 252.0, 486.7, 320.0], "size": 30.0}]$$),
    ('my-inside-weather', 12, $$$$, $$[]$$),
    ('my-inside-weather', 13, $$$$, $$[]$$),
    ('my-special-blankie', 0, $$Can you see me? I’m on Mama’s back in my special blankie.$$, $$[{"role": "BODY", "text": "Can you see me?", "bbox": [175.6, 204.1, 463.6, 239.1], "size": 35.0}, {"role": "BODY", "text": "I’m on Mama’s back in my special blankie.", "bbox": [133.2, 288.1, 506.1, 365.1], "size": 35.0}]$$),
    ('my-special-blankie', 1, $$I love Mama. And Mama loves me. And I love, love, LOVE my special blankie.$$, $$[{"role": "BODY", "text": "I love Mama. And Mama loves me.", "bbox": [103.1, 166.2, 463.9, 243.2], "size": 35.0}, {"role": "BODY", "text": "And I love, love, LOVE my special blankie.", "bbox": [715.4, 452.6, 1083.2, 529.6], "size": 35.0}]$$),
    ('my-special-blankie', 2, $$Boom! I like to make a noise. Bang! Bash!$$, $$[{"role": "BODY", "text": "Boom!", "bbox": [381.8, 261.2, 486.3, 306.3], "size": 35.0}, {"role": "BODY", "text": "I like to make a noise.", "bbox": [98.4, 415.2, 468.6, 450.2], "size": 35.0}, {"role": "BODY", "text": "Bang!", "bbox": [643.7, 149.4, 739.9, 197.7], "size": 34.7}, {"role": "BODY", "text": "Bash!", "bbox": [714.7, 244.5, 807.8, 289.4], "size": 34.1}]$$),
    ('my-special-blankie', 3, $$But Mama likes quiet. Shhh Shhh Shhh$$, $$[{"role": "BODY", "text": "But Mama likes quiet.", "bbox": [95.9, 111.9, 471.1, 146.9], "size": 35.0}, {"role": "BODY", "text": "Shhh Shhh Shhh", "bbox": [942.7, 90.5, 1077.2, 235.3], "size": 42.8}]$$),
    ('my-special-blankie', 4, $$Mama does her work. Go! Go! Go!$$, $$[{"role": "BODY", "text": "Mama does her work.", "bbox": [106.6, 213.7, 478.8, 248.7], "size": 35.0}, {"role": "BODY", "text": "Go!", "bbox": [764.2, 137.3, 820.0, 175.5], "size": 34.0}, {"role": "BODY", "text": "Go!", "bbox": [726.4, 235.9, 783.3, 276.5], "size": 34.9}, {"role": "BODY", "text": "Go!", "bbox": [812.6, 304.6, 870.0, 343.8], "size": 34.3}]$$),
    ('my-special-blankie', 5, $$Woah! And I like to play. Woah! Woah!$$, $$[{"role": "BODY", "text": "Woah!", "bbox": [420.5, 455.0, 523.4, 499.9], "size": 35.1}, {"role": "BODY", "text": "And I like to play.", "bbox": [754.0, 89.2, 1050.2, 124.2], "size": 35.0}, {"role": "BODY", "text": "Woah!", "bbox": [961.0, 250.0, 1064.7, 299.8], "size": 36.4}, {"role": "BODY", "text": "Woah!", "bbox": [986.9, 368.8, 1092.5, 415.6], "size": 35.5}]$$),
    ('my-special-blankie', 6, $$Oh, I love, love, LOVE my special blankie.$$, $$[{"role": "BODY", "text": "Oh, I love, love, LOVE my special blankie.", "bbox": [106.3, 253.2, 460.6, 330.2], "size": 35.0}]$$),
    ('my-special-blankie', 7, $$But when I eat, Mama says my special blankie must watch.$$, $$[{"role": "BODY", "text": "But when I eat, Mama says my special blankie must watch.", "bbox": [81.8, 116.7, 485.2, 235.7], "size": 35.0}]$$),
    ('my-special-blankie', 8, $$And when I wash, my special blankie must wait where it is dry.$$, $$[{"role": "BODY", "text": "And when I wash, my special blankie must wait where it is dry.", "bbox": [664.8, 109.3, 1036.0, 228.3], "size": 35.0}]$$),
    ('my-special-blankie', 9, $$I love bedtime stories with Mama. My special blankie listens with me ...$$, $$[{"role": "BODY", "text": "I love bedtime stories with Mama.", "bbox": [665.4, 190.2, 1035.4, 267.2], "size": 35.0}, {"role": "BODY", "text": "My special blankie listens with me ...", "bbox": [690.6, 316.2, 1010.2, 393.2], "size": 35.0}]$$),
    ('my-special-blankie', 10, $$... and helps me go to sleep.$$, $$[{"role": "BODY", "text": "... and helps me go to sleep.", "bbox": [148.9, 258.1, 418.1, 335.1], "size": 35.0}]$$),
    ('my-special-blankie', 11, $$I love, love, LOVE my special blankie.$$, $$[{"role": "BODY", "text": "I love, love, LOVE my special blankie.", "bbox": [118.1, 253.2, 448.8, 330.2], "size": 35.0}]$$),
