    ('my-special-blankie', 13, $$$$, $$[]$$),
    ('my-special-hair', 0, $$I have a very special head, a special head of hair. My special hair is quite unique. My special hair is rare.$$, $$[{"role": "BODY", "text": "I have a very special head, a special head of hair. My special hair is quite unique. My special hair is rare.", "bbox": [112.0, 225.2, 429.0, 351.2], "size": 24.0}]$$),
    ('my-special-hair', 1, $$It grows not just on any head, but mine, my own, just me! My special hair does special things – it’s magic hair, you see.$$, $$[{"role": "BODY", "text": "It grows not just on any head, but mine, my own, just me! My special hair does special things – it’s magic hair, you see.", "bbox": [82.6, 125.3, 453.4, 303.3], "size": 24.0}]$$),
    ('my-special-hair', 2, $$In summer when the sun is hot, with no shade anywhere, I do not sweat, I do not burn. I grow a hat of hair.$$, $$[{"role": "BODY", "text": "In summer when the sun is hot, with no shade anywhere, I do not sweat, I do not burn. I grow a hat of hair.", "bbox": [734.2, 165.5, 1055.9, 291.5], "size": 24.0}]$$),
    ('my-special-hair', 3, $$In winter when my nose turns red, and when the cold wind blows, my special hair grows very long. I’m wrapped from top to toes.$$, $$[{"role": "BODY", "text": "In winter when my nose turns red, and when the cold wind blows, my special hair grows very long. I’m wrapped from top to toes.", "bbox": [705.3, 123.2, 1056.0, 327.2], "size": 24.0}]$$),
    ('my-special-hair', 4, $$In spring when all the birds come out, and each one builds a nest, my head is full of songs because my special hair is best.$$, $$[{"role": "BODY", "text": "In spring when all the birds come out, and each one builds a nest, my head is full of songs because my special hair is best.", "bbox": [56.0, 298.7, 442.7, 424.7], "size": 24.0}]$$),
    ('my-special-hair', 5, $$In autumn when the leaves fall down, no flowers to be found, my special head begins to bloom bright blossoms all around.$$, $$[{"role": "BODY", "text": "In autumn when the leaves fall down, no flowers to be found, my special head begins to bloom bright blossoms all around.", "bbox": [99.2, 135.7, 484.0, 261.7], "size": 24.0}]$$),
    ('my-special-hair', 6, $$My special hair is stiff and strong. It does not hang or drape. I never look the same because my hair can change its shape.$$, $$[{"role": "BODY", "text": "My special hair is stiff and strong. It does not hang or drape. I never look the same because my hair can change its shape.", "bbox": [117.6, 216.5, 460.2, 342.5], "size": 24.0}]$$),
    ('my-special-hair', 7, $$My special hair is full of curls. It’s twisted, tangled, tough. My special hair grows hairy hands – a place to store my stuff.$$, $$[{"role": "BODY", "text": "My special hair is full of curls. It’s twisted, tangled, tough. My special hair grows hairy hands – a place to store my stuff.", "bbox": [731.3, 218.6, 1094.9, 404.6], "size": 24.0}]$$),
    ('my-special-hair', 8, $$My special hair grows special wings – so smooth, so soft, so light. They float around my face, until my hair and I take flight.$$, $$[{"role": "BODY", "text": "My special hair grows special wings – so smooth, so soft, so light. They float around my face, until my hair and I take flight.", "bbox": [140.3, 188.1, 520.3, 366.1], "size": 24.0}]$$),
    ('my-special-hair', 9, $$My special hair is colourful, a rainbow all in one! It brightens up the darkest day. My hair is full of fun.$$, $$[{"role": "BODY", "text": "My special hair is colourful, a rainbow all in one! It brightens up the darkest day. My hair is full of fun.", "bbox": [661.2, 164.3, 984.1, 290.3], "size": 24.0}]$$),
    ('my-special-hair', 10, $$My special hair is full of love. With love my head is crowned. It grows and grows and grows until I spread it all around.$$, $$[{"role": "BODY", "text": "My special hair is full of love. With love my head is crowned. It grows and grows and grows until I spread it all around.", "bbox": [76.5, 148.5, 407.8, 327.5], "size": 24.0}]$$),
    ('my-special-hair', 11, $$So many types of special heads, so many types of hair. Be proud of what you have on top, your magic grows up there!$$, $$[{"role": "BODY", "text": "So many types of special heads, so many types of hair. Be proud of what you have on top, your magic grows up there!", "bbox": [154.5, 165.9, 507.4, 291.9], "size": 24.0}]$$),
