    ('no', 4, $$Mama Come make help some rice. No!$$, $$[{"role": "BODY", "text": "Mama Come make help some rice.", "bbox": [179.0, 189.6, 378.7, 308.6], "size": 35.0}, {"role": "SFX", "text": "No!", "bbox": [690.3, 198.6, 776.0, 252.6], "size": 54.0}]$$),
    ('no', 5, $$Let’s feed Shakes. No!$$, $$[{"role": "BODY", "text": "Let’s feed Shakes.", "bbox": [650.5, 88.1, 926.9, 123.1], "size": 35.0}, {"role": "SFX", "text": "No!", "bbox": [889.1, 335.5, 974.8, 389.5], "size": 54.0}]$$),
    ('no', 6, $$Nosisi it’s bath time... No!$$, $$[{"role": "BODY", "text": "Nosisi it’s bath time...", "bbox": [683.4, 108.6, 1017.4, 143.6], "size": 35.0}, {"role": "SFX", "text": "No!", "bbox": [749.5, 315.3, 951.4, 442.5], "size": 127.2}]$$),
    ('no', 7, $$No No No No! Nonononono...$$, $$[{"role": "BODY", "text": "No", "bbox": [55.5, 66.8, 102.5, 101.8], "size": 35.0}, {"role": "BODY", "text": "No", "bbox": [347.1, 157.5, 394.2, 192.5], "size": 35.0}, {"role": "BODY", "text": "No", "bbox": [92.0, 460.1, 139.0, 495.1], "size": 35.0}, {"role": "SFX", "text": "No! Nonononono...", "bbox": [623.6, 341.1, 852.5, 497.2], "size": 53.4}]$$),
    ('no', 8, $$How about an ice cream? No!$$, $$[{"role": "BODY", "text": "How about an ice cream?", "bbox": [651.5, 83.8, 1049.4, 118.8], "size": 35.0}, {"role": "SFX", "text": "No!", "bbox": [810.0, 341.7, 895.7, 395.7], "size": 54.0}]$$),
    ('no', 9, $$Oh. Not no...$$, $$[{"role": "BODY", "text": "Oh. Not no...", "bbox": [217.5, 255.2, 349.5, 332.2], "size": 35.0}]$$),
    ('no', 10, $$Yes! Yummy. Yummy. Yay! Yay! Yay!$$, $$[{"role": "BODY", "text": "Yes! Yummy. Yummy.", "bbox": [137.7, 249.5, 403.0, 385.4], "size": 47.0}, {"role": "BODY", "text": "Yay!", "bbox": [635.8, 424.0, 702.2, 459.0], "size": 35.0}, {"role": "BODY", "text": "Yay!", "bbox": [981.6, 66.8, 1048.0, 101.8], "size": 35.0}, {"role": "BODY", "text": "Yay!", "bbox": [996.5, 390.0, 1062.9, 425.0], "size": 35.0}]$$),
    ('no', 11, $$Nosisi, will you tidy your room? Hmmmm. Well...okay.$$, $$[{"role": "BODY", "text": "Nosisi, will you tidy your room?", "bbox": [128.0, 250.2, 439.1, 327.2], "size": 35.0}, {"role": "BODY", "text": "Hmmmm. Well...okay.", "bbox": [678.5, 117.5, 1022.2, 152.5], "size": 35.0}]$$),
    ('no', 12, $$$$, $$[]$$),
